import React, { useEffect } from 'react';
import { BrowserRouter, Routes, Route, Navigate, useNavigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { DataProvider } from './context/DataContext';
import Login from './pages/Login';
import Sidebar from './components/common/Sidebar';
import TopBar from './components/common/TopBar';

// Admin Pages
import AdminDashboard from './pages/admin/AdminDashboard';
import UserManagement from './pages/admin/UserManagement';
import SeasonManagement from './pages/admin/SeasonManagement';
import FarmerRegistry from './pages/admin/FarmerRegistry';
import WorkerManagement from './pages/admin/WorkerManagement';
import LotOverview from './pages/admin/LotOverview';
import Reports from './pages/admin/Reports';
import Reports from './pages/admin/Reports';
import AuditLogs from './pages/admin/AuditLogs';
import ExcelFinancePortal from './pages/admin/ExcelFinancePortal';

// Receptionist Pages
import DeliveryEntry from './pages/receptionist/DeliveryEntry';
import DeliveryHistory from './pages/receptionist/DeliveryHistory';

// Operator Pages
import LotProcessing from './pages/operator/LotProcessing';
import ProcessingLogs from './pages/operator/ProcessingLogs';
import DryingMonitor from './pages/operator/DryingMonitor';
import DryingLogs from './pages/operator/DryingLogs';
import BagManagement from './pages/operator/BagManagement';

// Sustainability Pages
import QualityChecks from './pages/sustainability/QualityChecks';
import ComplianceChecks from './pages/sustainability/ComplianceChecks';
import LotApproval from './pages/sustainability/LotApproval';

// Finance Pages
import ExpenseManagement from './pages/finance/ExpenseManagement';
import LaborCosts from './pages/finance/LaborCosts';
import AssetManagement from './pages/finance/AssetManagement';
import RevenueManagement from './pages/finance/RevenueManagement';
import FinancialStatements from './pages/finance/FinancialStatements';
import KPIs from './pages/finance/KPIs';
import LoanManagement from './pages/finance/LoanManagement';
import FinancingSourceManagement from './pages/finance/FinancingSourceManagement';

import './App.css';

const ProtectedLayout = ({ children, allowedRole }) => {
  const { user } = useAuth();

  // Handle both string and array allowedRole
  const isAllowed = Array.isArray(allowedRole)
    ? allowedRole.includes(user?.role) || allowedRole.includes(user?.role?.toLowerCase())
    : user?.role === allowedRole || user?.role?.toLowerCase() === allowedRole;

  if (!isAllowed) {
    return <Navigate to={`/${user?.role === 'FINANCE' ? 'finance' : user?.role?.toLowerCase()}`} replace />;
  }

  return (
    <div className="app-layout">
      <Sidebar />
      <div className="app-main">
        <TopBar />
        <main className="app-content">{children}</main>
      </div>
    </div>
  );
};

const AppRoutes = () => {
  const { user, isLoading } = useAuth();
  const navigate = useNavigate();
  useEffect(() => {
    const handler = () => navigate('/login', { replace: true });
    window.addEventListener('unauthorized', handler);
    return () => window.removeEventListener('unauthorized', handler);
  }, [navigate]);

  // Show loading screen while checking auth state
  if (isLoading) {
    return (
      <div className="loading-screen">
        <div className="spinner"></div>
      </div>
    );
  }

  // If not loading but no user, show login
  if (!user) {
    return <Login />;
  }

  return (
    <Routes>
      {/* Admin Routes */}
      <Route path="/admin" element={<ProtectedLayout allowedRole="admin"><AdminDashboard /></ProtectedLayout>} />
      <Route path="/admin/users" element={<ProtectedLayout allowedRole="admin"><UserManagement /></ProtectedLayout>} />
      <Route path="/admin/seasons" element={<ProtectedLayout allowedRole="admin"><SeasonManagement /></ProtectedLayout>} />
      <Route path="/admin/farmers" element={<ProtectedLayout allowedRole="admin"><FarmerRegistry /></ProtectedLayout>} />
      <Route path="/admin/workers" element={<ProtectedLayout allowedRole="admin"><WorkerManagement /></ProtectedLayout>} />
      <Route path="/admin/lots" element={<ProtectedLayout allowedRole="admin"><LotOverview /></ProtectedLayout>} />
      <Route path="/admin/reports" element={<ProtectedLayout allowedRole="admin"><Reports /></ProtectedLayout>} />
      <Route path="/admin/audit" element={<ProtectedLayout allowedRole="admin"><AuditLogs /></ProtectedLayout>} />
      <Route path="/admin/excel-finances" element={<ProtectedLayout allowedRole={["admin", "finance", "FINANCE"]}><ExcelFinancePortal /></ProtectedLayout>} />

      {/* Receptionist Routes */}
      <Route path="/receptionist" element={<ProtectedLayout allowedRole="receptionist"><DeliveryEntry /></ProtectedLayout>} />
      <Route path="/receptionist/history" element={<ProtectedLayout allowedRole="receptionist"><DeliveryHistory /></ProtectedLayout>} />

      {/* Operator Routes */}
      <Route path="/operator" element={<ProtectedLayout allowedRole="operator"><LotProcessing /></ProtectedLayout>} />
      <Route path="/operator/logs" element={<ProtectedLayout allowedRole="operator"><ProcessingLogs /></ProtectedLayout>} />
      <Route path="/operator/drying-monitor" element={<ProtectedLayout allowedRole="operator"><DryingMonitor /></ProtectedLayout>} />
      <Route path="/operator/drying-logs" element={<ProtectedLayout allowedRole="operator"><DryingLogs /></ProtectedLayout>} />
      <Route path="/operator/bags" element={<ProtectedLayout allowedRole="operator"><BagManagement /></ProtectedLayout>} />

      {/* Sustainability Routes */}
      <Route path="/sustainability" element={<ProtectedLayout allowedRole="sustainability"><QualityChecks /></ProtectedLayout>} />
      <Route path="/sustainability/compliance" element={<ProtectedLayout allowedRole="sustainability"><ComplianceChecks /></ProtectedLayout>} />
      <Route path="/sustainability/approval" element={<ProtectedLayout allowedRole="sustainability"><LotApproval /></ProtectedLayout>} />

      {/* Finance Routes */}
      <Route path="/finance" element={<ProtectedLayout allowedRole={["finance", "FINANCE"]}><ExpenseManagement /></ProtectedLayout>} />
      <Route path="/finance/labor" element={<ProtectedLayout allowedRole={["finance", "FINANCE"]}><LaborCosts /></ProtectedLayout>} />
      <Route path="/finance/assets" element={<ProtectedLayout allowedRole={["finance", "FINANCE"]}><AssetManagement /></ProtectedLayout>} />
      <Route path="/finance/revenue" element={<ProtectedLayout allowedRole={["finance", "FINANCE"]}><RevenueManagement /></ProtectedLayout>} />
      <Route path="/finance/statements" element={<ProtectedLayout allowedRole={["finance", "FINANCE"]}><FinancialStatements /></ProtectedLayout>} />
      <Route path="/finance/kpis" element={<ProtectedLayout allowedRole={["finance", "FINANCE"]}><KPIs /></ProtectedLayout>} />
      <Route path="/finance/financing-sources" element={<ProtectedLayout allowedRole={["finance", "FINANCE"]}><FinancingSourceManagement /></ProtectedLayout>} />
      <Route path="/finance/loans" element={<ProtectedLayout allowedRole={["finance", "FINANCE"]}><LoanManagement /></ProtectedLayout>} />

      {/* Default redirect */}
      <Route path="*" element={<Navigate to={`/${user?.role === 'FINANCE' ? 'finance' : user?.role?.toLowerCase()}`} replace />} />
    </Routes>
  );
};

function App() {


  return (
    <BrowserRouter>
      <AuthProvider>
        <DataProvider>
          <AppRoutes />
        </DataProvider>
      </AuthProvider>
    </BrowserRouter>
  );
}

export default App;

import React, { useState } from 'react';
import { farmersAPI } from '../../services/api';
import { useData } from '../../context/DataContext';
import Modal from '../common/Modal';
import './AddFarmerForm.css';

const AddFarmerForm = ({ isOpen, onClose, onSuccess }) => {
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    sector: '',
    cell: '',
    village: '',
    idNumber: '',
    coffeeTrees: '',
    category: 'FARMER'
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState('');


  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const { fetchFarmers } = useData(); // Changed from refreshData to fetchFarmers

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setIsSubmitting(true);

    try {
      // Format phone number to Rwanda format if it exists
      let formattedPhone = formData.phone;
      if (formData.phone) {
        // Remove any non-digit characters
        const digits = formData.phone.replace(/\D/g, '');
        // If it starts with 0, replace with +250
        if (digits.startsWith('0')) {
          formattedPhone = `+250${digits.substring(1)}`;
        }
        // If it starts with 250, add the +
        else if (digits.startsWith('250')) {
          formattedPhone = `+${digits}`;
        }
        // If it's already in +250 format, leave as is
        else if (digits.startsWith('+250')) {
          formattedPhone = digits;
        }
        // Otherwise, assume it's a local number and add +250
        else {
          formattedPhone = `+250${digits}`;
        }
      }

      const formDataToSend = {
        name: formData.name,
        phone_number: formattedPhone || null,  // Will be null if no phone provided
        sector: formData.sector || null,
        cell: formData.cell || null,
        village: formData.village || null,
        id_card_number: formData.idNumber || null,
        number_of_coffee_trees: formData.coffeeTrees ? parseInt(formData.coffeeTrees, 10) : null,
        category: formData.category,
        active: true
      };

      const response = await farmersAPI.create(formDataToSend);
      await fetchFarmers();
      onSuccess('Farmer added successfully!');
      onClose();
    } catch (err) {
      console.error('Error adding farmer:', err);
      setError(err.response?.data?.message || 'Failed to add farmer. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  if (!isOpen) return null;

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={formData.category === 'ACHETEUR' ? "Add New Acheteur" : "Add New Farmer"}>
      <form onSubmit={handleSubmit} className="add-farmer-form">
        {error && <div className="alert alert-danger">{error}</div>}

        <div className="form-group">
          <label>Category *</label>
          <div className="category-toggle" style={{ display: 'flex', gap: '10px', marginBottom: '15px' }}>
            <button
              type="button"
              className={`btn ${formData.category === 'FARMER' ? 'btn-primary' : 'btn-outline-primary'}`}
              onClick={() => setFormData(prev => ({ ...prev, category: 'FARMER' }))}
              style={{ flex: 1 }}
            >
              Farmer
            </button>
            <button
              type="button"
              className={`btn ${formData.category === 'ACHETEUR' ? 'btn-primary' : 'btn-outline-primary'}`}
              onClick={() => setFormData(prev => ({ ...prev, category: 'ACHETEUR' }))}
              style={{ flex: 1 }}
            >
              Acheteur
            </button>
          </div>
        </div>

        <div className="form-group">
          <label>Full Name *</label>
          <input
            type="text"
            name="name"
            value={formData.name}
            onChange={handleChange}
            required
            className="form-control"
          />
        </div>

        <div className="form-group">
          <label>Phone Number</label>
          <input
            type="tel"
            name="phone"
            value={formData.phone}
            onChange={handleChange}
            className="form-control"
            placeholder="e.g., 0781234567 or +250781234567"
          />
          <small className="text-muted">Enter a Rwanda phone number (e.g., 0781234567 or +250781234567)</small>
        </div>

        <div className="form-row">
          <div className="form-group">
            <label>Sector *</label>
            <input
              type="text"
              name="sector"
              value={formData.sector}
              onChange={handleChange}
              required
              className="form-control"
            />
          </div>

          <div className="form-group">
            <label>Cell</label>
            <input
              type="text"
              name="cell"
              value={formData.cell}
              onChange={handleChange}
              className="form-control"
            />
          </div>
        </div>

        <div className="form-row">
          <div className="form-group">
            <label>Village</label>
            <input
              type="text"
              name="village"
              value={formData.village}
              onChange={handleChange}
              className="form-control"
            />
          </div>

          <div className="form-group">
            <label>ID/Passport Number</label>
            <input
              type="text"
              name="idNumber"
              value={formData.idNumber}
              onChange={handleChange}
              className="form-control"
            />
          </div>
        </div>

        <div className="form-group">
          <label>Number of Coffee Trees</label>
          <input
            type="number"
            name="coffeeTrees"
            value={formData.coffeeTrees}
            onChange={handleChange}
            className="form-control"
            min="0"
          />
        </div>

        <div className="form-actions">
          <button
            type="button"
            onClick={onClose}
            className="btn btn-secondary"
            disabled={isSubmitting}
          >
            Cancel
          </button>
          <button
            type="submit"
            className="btn btn-primary"
            disabled={isSubmitting}
          >
            {isSubmitting ? 'Adding...' : (formData.category === 'ACHETEUR' ? 'Add Acheteur' : 'Add Farmer')}
          </button>
        </div>
      </form>
    </Modal>
  );
};

export default AddFarmerForm;

// src/components/lots/AddLotForm.jsx
import React, { useEffect, useState } from 'react';
import { useData } from '../../context/DataContext';
import Modal from '../common/Modal';
import './addLotForm.css';
import { lotsAPI } from '../../services/api';

const AddLotForm = ({ isOpen, onClose, onSuccess }) => {
    const [formData, setFormData] = useState({
        lot_name: '',
        process_type: 'WASHED', // Default to WASHED as per backend
        status: 'CREATED', // Default status
        season_id: '',
        notes: ''
    });
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState('');
    const { fetchLots, seasons } = useData();

    const activeSeasons = seasons.filter(season => season.active === true);


    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({
            ...prev,
            [name]: value
        }));
    };

    

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');
        setIsSubmitting(true);

        try {
            // Ensure season_id is a number
            const dataToSend = {
                ...formData,
                season_id: formData.season_id,
            };
            console.log("Data to send: ",dataToSend);
            await lotsAPI.create(dataToSend);
            await fetchLots();
            onSuccess('Lot created successfully!');
            onClose();
        } catch (err) {
            console.error('Error creating lot:', err);
            setError(err.response?.data?.message || 'Failed to create lot. Please try again.');
        } finally {
            setIsSubmitting(false);
        }
    };

    if (!isOpen) return null;

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Create New Lot">
            <form onSubmit={handleSubmit} className="add-lot-form">
                {error && <div className="alert alert-danger">{error}</div>}
                
                <div className="form-group">
                    <label>Lot Name *</label>
                    <input
                        type="text"
                        name="lot_name"
                        value={formData.lot_name}
                        onChange={handleChange}
                        required
                        className="form-control"
                    />
                </div>

                <div className="form-row">
                    <div className="form-group">
                        <label>Process Type *</label>
                        <select
                            name="process_type"
                            value={formData.process_type}
                            onChange={handleChange}
                            required
                            className="form-control"
                        >
                            <option value="WASHED">Washed</option>
                            <option value="NATURAL">Natural</option>
                            <option value="HONEY">Honey</option>
                        </select>
                    </div>

                    <div className="form-group">
                        <label>Status *</label>
                        <select
                            name="status"
                            value={formData.status}
                            onChange={handleChange}
                            required
                            className="form-control"
                        >
                            <option value="CREATED">Created</option>
                            <option value="PROCESSING">Processing</option>
                            <option value="COMPLETED">Completed</option>
                            <option value="CANCELLED">Cancelled</option>
                        </select>
                    </div>
                </div>

                <div className="form-group">
                    <label>Season</label>
                    <select
                        name="season_id"
                        value={formData.season_id}
                        onChange={handleChange}
                        className="form-control"
                    >
                        <option value="">Select a season</option>
                        {seasons.map(season => (
                            <option key={season.id} value={season.id}>
                                {season.name} ({season?.start_date?.split('T')[0]} - {season.end_date ? season.end_date.split('T')[0] : 'Ongoing'})
                            </option>
                        ))}
                    </select>
                </div>

                <div className="form-group">
                    <label>Notes</label>
                    <textarea
                        name="notes"
                        value={formData.notes}
                        onChange={handleChange}
                        className="form-control"
                        rows="3"
                    />
                </div>

                <div className="form-actions">
                    <button
                        type="button"
                        onClick={onClose}
                        className="btn btn-secondary"
                        disabled={isSubmitting}
                    >
                        Cancel
                    </button>
                    <button
                        type="submit"
                        className="btn btn-primary"
                        disabled={isSubmitting}
                    >
                        {isSubmitting ? 'Creating...' : 'Create Lot'}
                    </button>
                </div>
            </form>
        </Modal>
    );
};

export default AddLotForm;

import React, { createContext, useContext, useState, useEffect } from 'react';
import { authAPI } from '../services/api';

const AuthContext = createContext();

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within AuthProvider');
  }
  return context;
};

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    let isMounted = true;
    
    const loadUser = async () => {
      try {
        const token = localStorage.getItem('token');
        
        if (!token) {
          setIsLoading(false);
          return;
        }
        
        // Only try to get fresh user data if we have a token
        const response = await authAPI.getProfile();
        if (isMounted) {
          const userData = response.data.data;
          setUser(userData);
          localStorage.setItem('user', JSON.stringify(userData));
        }
      } catch (error) {
        console.error('Error loading user:', error);
        // Clear invalid auth data
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        setUser(null);
      } finally {
        if (isMounted) {
          setIsLoading(false);
        }
      }
    };

    loadUser();
    
    return () => {
      isMounted = false;
    };
  }, []);

  const login = async (email, password) => {
    try {
      const response = await authAPI.login({ email, password });
      const { token, user } = response.data.data;
      
      // Store token and user data
      localStorage.setItem('token', token);
      localStorage.setItem('user', JSON.stringify(user));
      
      setUser(user);
      return { response };
    } catch (error) {
      console.error('Login error:', error);
      return { 
        success: false, 
        error: error.message || 'Invalid email or password' 
      };
    }
  };

  const logout = () => {
    // Clear auth data
    setUser(null);
    localStorage.removeItem('token');
    localStorage.removeItem('user');
  };

  return (
    <AuthContext.Provider value={{ user, login, logout, isLoading }}>
      {children}
    </AuthContext.Provider>
  );
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import {
    farmersAPI,
    deliveriesAPI,
    lotsAPI,
    storageAPI,
    expensesAPI,
    revenuesAPI,
    assetsAPI,
    seasonsAPI,
    laborLogsAPI,
    workersAPI,
    complianceLogsAPI,
    auditLogsAPI,
} from '../services/api';

const DataContext = createContext();

export const useData = () => {
    const context = useContext(DataContext);
    if (!context) {
        throw new Error('useData must be used within DataProvider');
    }
    return context;
};

export const DataProvider = ({ children }) => {
    // State management with loading and error states
    const [farmers, setFarmers] = useState([]);
    const [deliveries, setDeliveries] = useState([]);
    const [lots, setLots] = useState([]);
    const [bags, setBags] = useState([]);
    const [expenses, setExpenses] = useState([]);
    const [laborCosts, setLaborCosts] = useState([]);
    const [assets, setAssets] = useState([]);
    const [revenue, setRevenue] = useState([]);
    const [users, setUsers] = useState([]);
    const [seasons, setSeasons] = useState([]);
    const [qualityChecks, setQualityChecks] = useState([]);
    const [sustainabilityChecks, setSustainabilityChecks] = useState([]);
    const [auditLogs, setAuditLogs] = useState([]);

    // Loading states
    const [loading, setLoading] = useState({
        farmers: false,
        deliveries: false,
        lots: false,
        bags: false,
        expenses: false,
        laborCosts: false,
        assets: false,
        revenue: false,
        users: false,
        seasons: false,
        qualityChecks: false,
        sustainabilityChecks: false,
        auditLogs: false,
    });

    // Helper function to transform snake_case to camelCase
    const transformDelivery = (delivery) => ({
        id: delivery.id,
        farmerId: delivery.farmer_id,
        farmerName: delivery.farmer?.name || '',
        receptionistId: delivery.receptionist_id,
        seasonId: delivery.season_id,
        lotId: delivery.lot_id,
        date: delivery.delivery_date?.split('T')[0] || '',
        time: delivery.delivery_date ? new Date(delivery.delivery_date).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' }) : '',
        weight: parseFloat(delivery.weight_kg) || 0,
        unitPrice: parseFloat(delivery.unit_price) || 0,
        totalAmount: parseFloat(delivery.total_amount) || 0,
        qualityScore: delivery.quality_score || 0,
        paymentStatus: delivery.paid?.toLowerCase() || 'pending',
        season: delivery.season?.name || '',
    });

    const transformFarmer = (farmer) => ({
        id: farmer.id,
        name: farmer.name,
        phone: farmer.phone_number || '',
        sector: farmer.sector || '',
        cell: farmer.cell || '',
        village: farmer.village || '',
        farmType: farmer.farm_type || '',
        category: farmer.category || 'FARMER',
        idCardNumber: farmer.id_card_number || '',
        numberOfCoffeeTrees: farmer.number_of_coffee_trees || null,
        registeredDate: farmer.created_at?.split('T')[0] || '',
        active: farmer.active,
    });

    const transformLot = (lot) => ({
        id: lot.id,
        lotName: lot.lot_name,
        processingMethod: lot.process_type,
        grade: lot.grade || '',
        status: lot.status?.toLowerCase().replace('_', ' ') || 'created',
        seasonId: lot.season_id,
        createdDate: lot.created_at?.split('T')[0] || '',
        totalWeight: 0, // Will be calculated from deliveries
        timeline: [], // Will be populated from processing logs
    });

    // Fetch functions
    const fetchFarmers = async () => {
        try {
            setLoading(prev => ({ ...prev, farmers: true }));
            const response = await farmersAPI.getAll();
            const transformed = response.data.data.map(transformFarmer);
            setFarmers(transformed);
        } catch (error) {
            console.error('Error fetching farmers:', error);
            setFarmers([]);
        } finally {
            setLoading(prev => ({ ...prev, farmers: false }));
        }
    };

    const fetchDeliveries = async () => {
        try {
            setLoading(prev => ({ ...prev, deliveries: true }));
            const response = await deliveriesAPI.getAll();
            const transformed = response.data.data.map(transformDelivery);
            setDeliveries(transformed);
        } catch (error) {
            console.error('Error fetching deliveries:', error);
            setDeliveries([]);
        } finally {
            setLoading(prev => ({ ...prev, deliveries: false }));
        }
    };

    const fetchLots = async () => {
        try {
            setLoading(prev => ({ ...prev, lots: true }));
            const response = await lotsAPI.getAll();
            const transformed = response.data.data.map(transformLot);
            setLots(transformed);
        } catch (error) {
            console.error('Error fetching lots:', error);
            setLots([]);
        } finally {
            setLoading(prev => ({ ...prev, lots: false }));
        }
    };

    const fetchSeasons = async () => {
        try {
            setLoading(prev => ({ ...prev, seasons: true }));
            const response = await seasonsAPI.getAll();
            setSeasons(response.data.data || []);
        } catch (error) {
            console.error('Error fetching seasons:', error);
            setSeasons([]);
        } finally {
            setLoading(prev => ({ ...prev, seasons: false }));
        }
    };

    const fetchExpenses = async () => {
        try {
            setLoading(prev => ({ ...prev, expenses: true }));
            const response = await expensesAPI.getAll();
            setExpenses(response.data.data || []);
        } catch (error) {
            console.error('Error fetching expenses:', error);
            setExpenses([]);
        } finally {
            setLoading(prev => ({ ...prev, expenses: false }));
        }
    };

    const fetchRevenues = async () => {
        try {
            setLoading(prev => ({ ...prev, revenue: true }));
            const response = await revenuesAPI.getAll();
            setRevenue(response.data.data || []);
        } catch (error) {
            console.error('Error fetching revenues:', error);
            setRevenue([]);
        } finally {
            setLoading(prev => ({ ...prev, revenue: false }));
        }
    };

    const fetchAssets = async () => {
        try {
            setLoading(prev => ({ ...prev, assets: true }));
            const response = await assetsAPI.getAll();
            setAssets(response.data.data || []);
        } catch (error) {
            console.error('Error fetching assets:', error);
            setAssets([]);
        } finally {
            setLoading(prev => ({ ...prev, assets: false }));
        }
    };

    const fetchStorageBags = async () => {
        try {
            setLoading(prev => ({ ...prev, bags: true }));
            const response = await storageAPI.getAll();
            setBags(response.data.data || []);
        } catch (error) {
            console.error('Error fetching storage bags:', error);
            setBags([]);
        } finally {
            setLoading(prev => ({ ...prev, bags: false }));
        }
    };

    const fetchLaborLogs = async () => {
        try {
            setLoading(prev => ({ ...prev, laborCosts: true }));
            const response = await laborLogsAPI.getAll();
            setLaborCosts(response.data.data || []);
        } catch (error) {
            console.error('Error fetching labor logs:', error);
            setLaborCosts([]);
        } finally {
            setLoading(prev => ({ ...prev, laborCosts: false }));
        }
    };

    const fetchAuditLogs = async (params = {}) => {
        try {
            setLoading(prev => ({ ...prev, auditLogs: true }));
            const response = await auditLogsAPI.getAll(params);
            setAuditLogs(response.data.data || []);
        } catch (error) {
            console.error('Error fetching audit logs:', error);
            setAuditLogs([]);
        } finally {
            setLoading(prev => ({ ...prev, auditLogs: false }));
        }
    };

    // Initial data fetch
    useEffect(() => {
        fetchFarmers();
        fetchDeliveries();
        fetchLots();
        fetchSeasons();
        fetchExpenses();
        fetchRevenues();
        fetchAssets();
        fetchStorageBags();
        fetchLaborLogs();
    }, []);

    const value = {
        // Data
        farmers,
        deliveries,
        lots,
        bags,
        expenses,
        laborCosts,
        assets,
        revenue,
        users,
        seasons,
        qualityChecks,
        sustainabilityChecks,
        auditLogs,
        // Setters (for optimistic updates)
        setFarmers,
        setDeliveries,
        setLots,
        setBags,
        setExpenses,
        setLaborCosts,
        setAssets,
        setRevenue,
        setUsers,
        setSeasons,
        setQualityChecks,
        setSustainabilityChecks,
        setAuditLogs,
        // Fetch functions (for refresh)
        fetchFarmers,
        fetchDeliveries,
        fetchLots,
        fetchSeasons,
        fetchExpenses,
        fetchRevenues,
        fetchAssets,
        fetchStorageBags,
        fetchLaborLogs,
        fetchAuditLogs,
        // Loading states
        loading,
    };

    return <DataContext.Provider value={value}>{children}</DataContext.Provider>;
};

