import React, { useState, useEffect } from 'react';
import { excelFinancesAPI } from '../../services/api';
import Modal from '../../components/common/Modal';
import ExcelAddEntryForm from '../../components/finances/ExcelAddEntryForm';
import { toast } from 'react-toastify';
import './ExcelFinancePortal.css';

const SHEETS = ['Staff', 'Admin Costs', 'Maint & Bags'];

const ExcelFinancePortal = () => {
    const [fileStatus, setFileStatus] = useState(null);
    const [isLoading, setIsLoading] = useState(true);
    const [uploading, setUploading] = useState(false);

    // Sheet Data State
    const [activeTab, setActiveTab] = useState(SHEETS[0]);
    const [sheetData, setSheetData] = useState([]);
    const [sheetHeaders, setSheetHeaders] = useState([]);
    const [loadingSheet, setLoadingSheet] = useState(false);

    // Modal State
    const [isAddModalOpen, setIsAddModalOpen] = useState(false);

    useEffect(() => {
        checkStatus();
    }, []);

    useEffect(() => {
        if (fileStatus?.exists) {
            fetchSheet(activeTab);
        }
    }, [activeTab, fileStatus]);

    const checkStatus = async () => {
        try {
            const res = await excelFinancesAPI.status();
            setFileStatus(res.data);
        } catch (error) {
            console.error('Error checking excel status:', error);
            toast.error('Failed to check backend file status.');
        } finally {
            setIsLoading(false);
        }
    };

    const handleUpload = async (e) => {
        const file = e.target.files[0];
        if (!file) return;

        setUploading(true);
        const formData = new FormData();
        formData.append('file', file);

        try {
            await excelFinancesAPI.upload(formData);
            toast.success('Excel template uploaded successfully!');
            checkStatus(); // Refresh status which will trigger sheet fetch
        } catch (err) {
            toast.error(err.response?.data?.message || 'Failed to upload file');
        } finally {
            setUploading(false);
            // Reset input
            e.target.value = null;
        }
    };

    const fetchSheet = async (sheetName) => {
        setLoadingSheet(true);
        try {
            const res = await excelFinancesAPI.getSheet(sheetName);
            setSheetHeaders(res.data.headers || []);
            setSheetData(res.data.data || []);
        } catch (error) {
            toast.error(`Error loading sheet: ${sheetName}`);
            setSheetData([]);
            setSheetHeaders([]);
        } finally {
            setLoadingSheet(false);
        }
    };

    const handleAddSuccess = () => {
        setIsAddModalOpen(false);
        toast.success('Row added to Excel successfully');
        fetchSheet(activeTab); // Refresh the current sheet
    };

    if (isLoading) {
        return <div style={{ padding: '2rem', textAlign: 'center' }}>Loading Finance Portal...</div>;
    }

    if (fileStatus && !fileStatus.exists) {
        return (
            <div className="excel-finance-portal">
                <div className="page-header">
                    <h1 className="page-title">Financial Records</h1>
                    <p className="page-description">Manage station finances directly via Excel Template</p>
                </div>
                <div className="content-card upload-prompt">
                    <h2>Excel Template Missing</h2>
                    <p>The core financial template "2025 T M QUALITY PRODUCTION   Financial Statements.xls" is not found on the server.</p>
                    <p>Please upload the Excel template to enable the financial portal.</p>
                    <div className="upload-container">
                        <label className="btn btn-primary" style={{ cursor: 'pointer', display: 'inline-block' }}>
                            {uploading ? 'Uploading...' : 'Upload Excel Template'}
                            <input
                                type="file"
                                accept=".xls,.xlsx"
                                onChange={handleUpload}
                                style={{ display: 'none' }}
                                disabled={uploading}
                            />
                        </label>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="excel-finance-portal">
            <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                    <h1 className="page-title">Financial Records</h1>
                    <p className="page-description">Manage station finances directly via Excel Template</p>
                </div>
                <button
                    className="btn btn-primary"
                    onClick={() => setIsAddModalOpen(true)}
                >
                    + Add Entry to {activeTab}
                </button>
            </div>

            <div className="tabs-container">
                {SHEETS.map(sheet => (
                    <button
                        key={sheet}
                        className={`tab-btn ${activeTab === sheet ? 'active' : ''}`}
                        onClick={() => setActiveTab(sheet)}
                    >
                        {sheet}
                    </button>
                ))}
            </div>

            <div className="content-card">
                <h2 className="section-title">{activeTab} Sheet Details</h2>
                {loadingSheet ? (
                    <div style={{ padding: '2rem', textAlign: 'center' }}>Loading sheet data...</div>
                ) : sheetData.length === 0 ? (
                    <div style={{ padding: '2rem', textAlign: 'center' }}>No tabular data parsed for this sheet.</div>
                ) : (
                    <div className="table-container">
                        <table className="excel-table">
                            <thead>
                                <tr>
                                    {sheetHeaders.map((header, idx) => (
                                        <th key={idx}>{header}</th>
                                    ))}
                                </tr>
                            </thead>
                            <tbody>
                                {sheetData.map((row, rowIdx) => (
                                    <tr key={rowIdx}>
                                        {sheetHeaders.map((header, colIdx) => {
                                            const cellVal = row[header];
                                            return <td key={colIdx}>{cellVal !== null && cellVal !== undefined ? String(cellVal) : ''}</td>
                                        })}
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            <Modal isOpen={isAddModalOpen} onClose={() => setIsAddModalOpen(false)} title={`Add Entry to ${activeTab}`}>
                <ExcelAddEntryForm
                    sheetName={activeTab}
                    headers={sheetHeaders}
                    onSuccess={handleAddSuccess}
                    onCancel={() => setIsAddModalOpen(false)}
                />
            </Modal>
        </div>
    );
};

export default ExcelFinancePortal;

