import React, { useState, useEffect } from 'react';
import './PricingConfig.css';
import { pricingAPI } from '../../services/pricingAPI';
import priceImage from '../../assets/price-image.png';

const PricingConfig = () => {
    const [currentPricing, setCurrentPricing] = useState(null);
    const [priceHistory, setPriceHistory] = useState([]);
    const [newPrice, setNewPrice] = useState('');
    const [newSeason, setNewSeason] = useState('');
    const [effectiveDate, setEffectiveDate] = useState('');
    const [loading, setLoading] = useState(false);

    // Load current pricing and history
    useEffect(() => {
        const loadPricingData = async () => {
            try {
                // Load current pricing
                const currentRes = await pricingAPI.getCurrent();
                if (currentRes.data.success) {
                    setCurrentPricing(currentRes.data.data);
                    setNewPrice(currentRes.data.data.unit_price.toString());
                    
                    // Auto-set season if available
                    if (currentRes.data.data.season_name) {
                        setNewSeason(currentRes.data.data.season_name);
                    }
                }

                // Load pricing history
                const historyRes = await pricingAPI.getHistory();
                if (historyRes.data.success) {
                    setPriceHistory(historyRes.data.data);
                }
            } catch (error) {
                console.error('Error loading pricing data:', error);
            }
        };

        loadPricingData();
    }, []);

    const handleUpdatePrice = async (e) => {
        e.preventDefault();

        if (!newPrice || !newSeason) {
            alert('Please enter both price and season name');
            return;
        }

        setLoading(true);
        try {
            await pricingAPI.create({
                season_name: newSeason,
                unit_price: parseFloat(newPrice),
                effective_date: effectiveDate || new Date().toISOString().split('T')[0]
            });

            // Refresh data
            const currentRes = await pricingAPI.getCurrent();
            if (currentRes.data.success) {
                setCurrentPricing(currentRes.data.data);
            }

            const historyRes = await pricingAPI.getHistory();
            if (historyRes.data.success) {
                setPriceHistory(historyRes.data.data);
            }

            // Reset form
            setNewPrice('');
            setNewSeason('');
            setEffectiveDate('');

            alert(`Price updated to RWF ${newPrice} per kg for season ${newSeason}`);
        } catch (error) {
            console.error('Error updating price:', error);
            alert('Failed to update price');
        } finally {
            setLoading(false);
        }
    };

    const formatDate = (dateString) => {
        if (!dateString) return '';
        const date = new Date(dateString);
        return date.toLocaleDateString('en-US', { 
            year: 'numeric', 
            month: 'short', 
            day: 'numeric' 
        });
    };

    return (
        <div className="pricing-config">
            <div className="page-header">
                <h1 className="page-title">Pricing Configuration</h1>
                <p className="page-description">Manage coffee pricing by season and update current season prices</p>
            </div>

            <div className="pricing-layout">
                {/* Row 1: Cards */}
                <div className="pricing-cards-row">
                    {/* Current Price and Input */}
                    <div className="pricing-card">
                        <h3>Current Price</h3>
                        <form onSubmit={handleUpdatePrice}>
                            <label className="unit-label">Season Name</label>
                            <div className="price-input-container">
                                <input
                                    type="text"
                                    className="price-input"
                                    value={newSeason}
                                    onChange={(e) => setNewSeason(e.target.value)}
                                    placeholder={currentPricing?.season_name || "e.g., 2025A"}
                                />
                            </div>
                            <label className="unit-label">Unit Price RWF/Kg</label>
                            <div className="price-input-container">
                                <input
                                    type="number"
                                    className="price-input"
                                    value={newPrice}
                                    onChange={(e) => setNewPrice(e.target.value)}
                                    placeholder={currentPricing?.unit_price || "350"}
                                />
                            </div>
                            <button type="submit" className="btn-update-price">
                                Update
                            </button>
                        </form>
                    </div>

                    {/* Chart Card */}
                    <div className="pricing-card">
                        <h4 className="chart-title">Change of Price Per Season</h4>
                        <div className="chart-container">
                            {/* SVG Line Chart */}
                            <svg width="100%" height="100%" viewBox="0 0 300 200" preserveAspectRatio="none">
                                {/* Grid Lines */}
                                <line x1="0" y1="50" x2="300" y2="50" stroke="#f3f4f6" strokeWidth="1" />
                                <line x1="0" y1="100" x2="300" y2="100" stroke="#f3f4f6" strokeWidth="1" />
                                <line x1="0" y1="150" x2="300" y2="150" stroke="#f3f4f6" strokeWidth="1" />

                                {/* Line Path - Approximated based on data */}
                                <path
                                    d="M 10 93 L 100 63 L 190 63 L 290 50"
                                    fill="none"
                                    stroke="#8B5CF6"
                                    strokeWidth="2"
                                />

                                {/* Dots */}
                                <circle cx="10" cy="93" r="3" fill="#8B5CF6" />
                                <circle cx="100" cy="63" r="3" fill="#8B5CF6" />
                                <circle cx="190" cy="63" r="3" fill="#8B5CF6" />
                                <circle cx="290" cy="50" r="3" fill="#8B5CF6" />
                            </svg>

                            {/* Labels - absolutely positioned over SVG */}
                            <div className="chart-y-axis">
                                <span>600</span>
                                <span>400</span>
                                <span>200</span>
                                <span>0</span>
                            </div>
                            <div className="chart-x-axis">
                                <span>2024A</span>
                                <span>2025B</span>
                                <span>2026A</span>
                                <span>2026B</span>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Row 2: History and Image */}
                <div className="pricing-bottom-row">
                    {/* Price History Table */}
                    <div className="history-section">
                        <h3 className="section-title">Price History</h3>
                        <table className="price-history-table">
                            <thead>
                                <tr>
                                    <th className="col-season">SEASON</th>
                                    <th>PRICE (RWF/KG)</th>
                                    <th className="col-created">CREATED</th>
                                </tr>
                            </thead>
                            <tbody>
                                {priceHistory.map((item, index) => (
                                    <tr key={index}>
                                        <td className="col-season">{item.season}</td>
                                        <td>{item.price}</td>
                                        <td className="col-created">{item.created}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>

                    <div className="pricing-visuals">
                        <img src={priceImage} alt="Pricing Illustration" className="pricing-illustration" />
                    </div>
                </div>
            </div>
        </div>
    );
};

export default PricingConfig;

import React, { useState, useEffect } from 'react';
import { useData } from '../../context/DataContext';
import { financeSummariesAPI, auditLogsAPI } from '../../services/api';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';
import './Reports.css';

const Reports = () => {
    const { seasons, expenses, loading } = useData();
    const [isGenerating, setIsGenerating] = useState(false);
    const [currentSeason, setCurrentSeason] = useState(null);
    const [incomeData, setIncomeData] = useState(null);
    const [cashFlowData, setCashFlowData] = useState(null);
    const [auditStats, setAuditStats] = useState(null);
    const [auditLogs, setAuditLogs] = useState([]);
    const [reportsLoading, setReportsLoading] = useState(false);

    useEffect(() => {
        const activeSeason = seasons.find(s => s.active === true || s.status === 'ACTIVE' || s.status === 'active');
        setCurrentSeason(activeSeason || seasons[0] || null);
        console.log('Reports - seasons:', seasons);
        console.log('Reports - activeSeason:', activeSeason);
    }, [seasons]);

    useEffect(() => {
        if (currentSeason) {
            console.log('Reports - currentSeason set, loading data:', currentSeason);
            loadReportData();
        } else {
            console.log('Reports - no currentSeason available');
            setReportsLoading(false);
        }
    }, [currentSeason]);

    const loadReportData = async () => {
        if (!currentSeason) return;
        
        console.log('Reports - loadReportData starting for season:', currentSeason.id);
        setReportsLoading(true);
        try {
            // Load income statement data
            try {
                const incomeRes = await financeSummariesAPI.getIncomeStatement({ season_id: currentSeason.id });
                console.log('Reports - income statement response:', incomeRes);
                console.log('Reports - income statement data structure:', incomeRes.data);
                console.log('Reports - income statement success check:', incomeRes.data?.success);
                if (incomeRes.data?.success) {
                    setIncomeData(incomeRes.data.data);
                    console.log('Reports - income data set:', incomeRes.data.data);
                } else {
                    console.warn('Reports - income statement not successful:', incomeRes.data);
                    // Try to set data anyway if response exists
                    if (incomeRes.data) {
                        setIncomeData(incomeRes.data);
                        console.log('Reports - income data set from direct response:', incomeRes.data);
                    }
                }
            } catch (incomeError) {
                console.error('Reports - income statement error:', incomeError);
            }

            // Load cash flow data
            try {
                const cashFlowRes = await financeSummariesAPI.getCashFlow({ season_id: currentSeason.id });
                console.log('Reports - cash flow response:', cashFlowRes);
                console.log('Reports - cash flow data structure:', cashFlowRes.data);
                console.log('Reports - cash flow success check:', cashFlowRes.data?.success);
                if (cashFlowRes.data?.success) {
                    setCashFlowData(cashFlowRes.data.data);
                    console.log('Reports - cash flow data set:', cashFlowRes.data.data);
                } else {
                    console.warn('Reports - cash flow not successful:', cashFlowRes.data);
                    // Try to set data anyway if response exists
                    if (cashFlowRes.data) {
                        setCashFlowData(cashFlowRes.data);
                        console.log('Reports - cash flow data set from direct response:', cashFlowRes.data);
                    }
                }
            } catch (cashFlowError) {
                console.error('Reports - cash flow error:', cashFlowError);
            }

            // Load audit log stats
            try {
                const auditStatsRes = await auditLogsAPI.getStats();
                console.log('Reports - audit stats response:', auditStatsRes);
                console.log('Reports - audit stats data structure:', auditStatsRes.data);
                console.log('Reports - audit stats success check:', auditStatsRes.data?.success);
                if (auditStatsRes.data?.success) {
                    setAuditStats(auditStatsRes.data.data);
                    console.log('Reports - audit stats data set:', auditStatsRes.data.data);
                } else {
                    console.warn('Reports - audit stats not successful:', auditStatsRes.data);
                    // Try to set data anyway if response exists
                    if (auditStatsRes.data) {
                        setAuditStats(auditStatsRes.data);
                        console.log('Reports - audit stats data set from direct response:', auditStatsRes.data);
                    }
                }
            } catch (auditStatsError) {
                console.error('Reports - audit stats error:', auditStatsError);
            }

            // Load recent audit logs
            try {
                const auditLogsRes = await auditLogsAPI.getAll({ limit: 100 });
                console.log('Reports - audit logs response:', auditLogsRes);
                console.log('Reports - audit logs data structure:', auditLogsRes.data);
                console.log('Reports - audit logs success check:', auditLogsRes.data?.success);
                if (auditLogsRes.data?.success) {
                    setAuditLogs(auditLogsRes.data.data || []);
                    console.log('Reports - audit logs data set:', auditLogsRes.data.data);
                } else {
                    console.warn('Reports - audit logs not successful:', auditLogsRes.data);
                    // Try to set data anyway if response exists
                    if (auditLogsRes.data) {
                        setAuditLogs(auditLogsRes.data.data || auditLogsRes.data || []);
                        console.log('Reports - audit logs data set from direct response:', auditLogsRes.data.data || auditLogsRes.data);
                    }
                }
            } catch (auditLogsError) {
                console.error('Reports - audit logs error:', auditLogsError);
            }
        } catch (error) {
            console.error('Reports - general error loading report data:', error);
        } finally {
            console.log('Reports - loadReportData completed, setting loading to false');
            setReportsLoading(false);
        }
    };

    // Reports that can be integrated with backend
    const reports = [
        {
            id: 1,
            title: currentSeason ? `Income Statement - ${currentSeason.name}` : 'Income Statement',
            type: 'income-statement',
            accent: 'brown',
            iconBg: 'brown',
            iconColor: 'brown'
        },
        {
            id: 2,
            title: currentSeason ? `Expense Report - ${currentSeason.name}` : 'Expense Report',
            type: 'expense-report',
            accent: 'purple',
            iconBg: 'purple',
            iconColor: 'purple'
        },
        {
            id: 3,
            title: currentSeason ? `Cash Flow Statement - ${currentSeason.name}` : 'Cash Flow Statement',
            type: 'cash-flow',
            accent: 'orange',
            iconBg: 'orange',
            iconColor: 'orange'
        },
        {
            id: 4,
            title: `Audit Log Summary`,
            type: 'audit-log',
            accent: 'blue',
            iconBg: 'blue',
            iconColor: 'blue'
        }
    ];

    const generateReportContent = (reportType) => {
        const tempDiv = document.createElement('div');
        tempDiv.style.cssText = `
            width: 800px;
            padding: 40px;
            font-family: 'Arial', sans-serif;
            font-size: 14px;
            line-height: 1.4;
            color: #333;
            background: white;
            margin: 0 auto;
        `;

        let content = '';

        switch (reportType) {
            case 'income-statement':
                content = generateIncomeStatementContent();
                break;
            case 'expense-report':
                content = generateExpenseReportContent();
                break;
            case 'cash-flow':
                content = generateCashFlowContent();
                break;
            case 'audit-log':
                content = generateAuditLogContent();
                break;
            default:
                content = '<p>Report not available</p>';
        }

        tempDiv.innerHTML = content;
        return tempDiv;
    };

    const generateIncomeStatementContent = () => {
        if (!incomeData) {
            return '<p>Loading income statement data...</p>';
        }

        const totalRevenue = incomeData.totalRevenue || 0;
        const totalExpenses = incomeData.totalExpenses || 0;
        const netIncome = incomeData.netIncome || 0;

        return `
            <div style="text-align: center; margin-bottom: 30px;">
                <h1 style="margin: 0; color: #2c3e50; font-size: 28px; font-weight: bold;">Income Statement</h1>
                <p style="margin: 10px 0 0 0; color: #666; font-size: 16px;">${currentSeason ? `Season: ${currentSeason.name}` : 'All Seasons'}</p>
                <p style="margin: 5px 0 0 0; color: #666; font-size: 14px;">Generated on ${new Date().toLocaleDateString()}</p>
            </div>
            
            <div style="border-bottom: 2px solid #e0e0e0; margin: 30px 0;"></div>
            
            <table style="width: 100%; border-collapse: collapse;">
                <tr style="background-color: #f8f9fa; font-weight: bold;">
                    <td style="padding: 12px 8px; border-bottom: 1px solid #ddd;">Revenue</td>
                    <td style="padding: 12px 8px; text-align: right; border-bottom: 1px solid #ddd;">RWF ${totalRevenue.toLocaleString()}</td>
                </tr>
                <tr>
                    <td style="padding: 12px 8px; padding-left: 30px; border-bottom: 1px solid #ddd;">Sales Revenue</td>
                    <td style="padding: 12px 8px; text-align: right; border-bottom: 1px solid #ddd;">RWF ${totalRevenue.toLocaleString()}</td>
                </tr>
                <tr style="background-color: #f8f9fa; font-weight: bold;">
                    <td style="padding: 12px 8px; border-bottom: 1px solid #ddd;">Gross Profit</td>
                    <td style="padding: 12px 8px; text-align: right; border-bottom: 1px solid #ddd;">RWF ${totalRevenue.toLocaleString()}</td>
                </tr>
                <tr>
                    <td style="padding: 12px 8px; padding-left: 30px; border-bottom: 1px solid #ddd;">Operating Expenses</td>
                    <td style="padding: 12px 8px; text-align: right; border-bottom: 1px solid #ddd;">RWF ${totalExpenses.toLocaleString()}</td>
                </tr>
                <tr style="background-color: #e9ecef; font-weight: bold; font-size: 16px;">
                    <td style="padding: 15px 8px; color: ${netIncome >= 0 ? '#28a745' : '#dc3545'};">Net Profit / (Loss)</td>
                    <td style="padding: 15px 8px; text-align: right; color: ${netIncome >= 0 ? '#28a745' : '#dc3545'};">RWF ${netIncome.toLocaleString()}</td>
                </tr>
            </table>
        `;
    };

    const generateExpenseReportContent = () => {
        const seasonExpenses = currentSeason ? expenses.filter(e => e.season_id === currentSeason.id) : expenses;
        
        // Group expenses by category
        const expensesByCategory = {};
        seasonExpenses.forEach(expense => {
            const category = expense.category || 'Uncategorized';
            if (!expensesByCategory[category]) {
                expensesByCategory[category] = {
                    category: category,
                    total: 0,
                    count: 0,
                    items: []
                };
            }
            expensesByCategory[category].total += parseFloat(expense.amount || 0);
            expensesByCategory[category].count++;
            expensesByCategory[category].items.push(expense);
        });

        const totalExpenses = Object.values(expensesByCategory).reduce((sum, cat) => sum + cat.total, 0);

        let tableRows = '';
        Object.values(expensesByCategory).forEach(category => {
            tableRows += `
                <tr>
                    <td style="padding: 10px 8px; border-bottom: 1px solid #ddd;">${category.category}</td>
                    <td style="padding: 10px 8px; text-align: right; border-bottom: 1px solid #ddd;">${category.count}</td>
                    <td style="padding: 10px 8px; text-align: right; border-bottom: 1px solid #ddd;">RWF ${category.total.toLocaleString()}</td>
                    <td style="padding: 10px 8px; text-align: right; border-bottom: 1px solid #ddd;">RWF ${category.count > 0 ? (category.total / category.count).toLocaleString() : 0}</td>
                </tr>
            `;
        });

        return `
            <div style="text-align: center; margin-bottom: 30px;">
                <h1 style="margin: 0; color: #2c3e50; font-size: 28px; font-weight: bold;">Expense Report</h1>
                <p style="margin: 10px 0 0 0; color: #666; font-size: 16px;">${currentSeason ? `Season: ${currentSeason.name}` : 'All Seasons'}</p>
                <p style="margin: 5px 0 0 0; color: #666; font-size: 14px;">Generated on ${new Date().toLocaleDateString()}</p>
            </div>
            
            <div style="border-bottom: 2px solid #e0e0e0; margin: 30px 0;"></div>
            
            <div style="margin-bottom: 20px;">
                <h3 style="color: #2c3e50; margin-bottom: 10px;">Summary</h3>
                <p><strong>Total Expenses:</strong> RWF ${totalExpenses.toLocaleString()}</p>
                <p><strong>Categories:</strong> ${Object.keys(expensesByCategory).length}</p>
                <p><strong>Total Transactions:</strong> ${seasonExpenses.length}</p>
            </div>
            
            <table style="width: 100%; border-collapse: collapse;">
                <thead>
                    <tr style="background-color: #f8f9fa; font-weight: bold;">
                        <th style="padding: 12px 8px; text-align: left; border-bottom: 2px solid #ddd;">Category</th>
                        <th style="padding: 12px 8px; text-align: right; border-bottom: 2px solid #ddd;">Count</th>
                        <th style="padding: 12px 8px; text-align: right; border-bottom: 2px solid #ddd;">Total Amount</th>
                        <th style="padding: 12px 8px; text-align: right; border-bottom: 2px solid #ddd;">Average</th>
                    </tr>
                </thead>
                <tbody>
                    ${tableRows || '<tr><td colspan="4" style="padding: 20px; text-align: center;">No expenses found</td></tr>'}
                    <tr style="background-color: #e9ecef; font-weight: bold; font-size: 16px;">
                        <td style="padding: 15px 8px;">Total</td>
                        <td style="padding: 15px 8px; text-align: right;">${seasonExpenses.length}</td>
                        <td style="padding: 15px 8px; text-align: right;">RWF ${totalExpenses.toLocaleString()}</td>
                        <td style="padding: 15px 8px; text-align: right;">RWF ${seasonExpenses.length > 0 ? (totalExpenses / seasonExpenses.length).toLocaleString() : 0}</td>
                    </tr>
                </tbody>
            </table>
        `;
    };

    const generateCashFlowContent = () => {
        if (!cashFlowData) {
            return '<p>Loading cash flow data...</p>';
        }

        const cashInflows = cashFlowData.cashInflows || 0;
        const cashOutflows = cashFlowData.cashOutflows || 0;
        const netCashFlow = cashFlowData.netCashFlow || 0;

        return `
            <div style="text-align: center; margin-bottom: 30px;">
                <h1 style="margin: 0; color: #2c3e50; font-size: 28px; font-weight: bold;">Cash Flow Statement</h1>
                <p style="margin: 10px 0 0 0; color: #666; font-size: 16px;">${currentSeason ? `Season: ${currentSeason.name}` : 'All Seasons'}</p>
                <p style="margin: 5px 0 0 0; color: #666; font-size: 14px;">Generated on ${new Date().toLocaleDateString()}</p>
            </div>
            
            <div style="border-bottom: 2px solid #e0e0e0; margin: 30px 0;"></div>
            
            <table style="width: 100%; border-collapse: collapse;">
                <tr style="background-color: #f8f9fa; font-weight: bold;">
                    <td style="padding: 12px 8px; border-bottom: 1px solid #ddd;">Operating Activities</td>
                    <td style="padding: 12px 8px; text-align: right; border-bottom: 1px solid #ddd;"></td>
                </tr>
                <tr>
                    <td style="padding: 12px 8px; padding-left: 30px; border-bottom: 1px solid #ddd;">Cash from Sales</td>
                    <td style="padding: 12px 8px; text-align: right; border-bottom: 1px solid #ddd;">RWF ${cashInflows.toLocaleString()}</td>
                </tr>
                <tr>
                    <td style="padding: 12px 8px; padding-left: 30px; border-bottom: 1px solid #ddd;">Cash for Operations</td>
                    <td style="padding: 12px 8px; text-align: right; border-bottom: 1px solid #ddd;">(RWF ${cashOutflows.toLocaleString()})</td>
                </tr>
                <tr style="background-color: #e9ecef; font-weight: bold; font-size: 16px;">
                    <td style="padding: 15px 8px; color: ${netCashFlow >= 0 ? '#28a745' : '#dc3545'};">Net Cash from Operating Activities</td>
                    <td style="padding: 15px 8px; text-align: right; color: ${netCashFlow >= 0 ? '#28a745' : '#dc3545'};">RWF ${netCashFlow.toLocaleString()}</td>
                </tr>
            </table>
        `;
    };

    const generateAuditLogContent = () => {
        if (!auditStats && auditLogs.length === 0) {
            return '<p>Loading audit log data...</p>';
        }

        // Count actions by type
        const actionCounts = {};
        auditLogs.forEach(log => {
            const action = log.action || 'UNKNOWN';
            actionCounts[action] = (actionCounts[action] || 0) + 1;
        });

        const totalActivities = auditLogs.length;
        const uniqueUsers = new Set(auditLogs.map(log => log.name || log.user?.name).filter(Boolean)).size;

        let actionRows = '';
        Object.entries(actionCounts)
            .sort((a, b) => b[1] - a[1])
            .forEach(([action, count]) => {
                const percentage = totalActivities > 0 ? ((count / totalActivities) * 100).toFixed(1) : 0;
                actionRows += `
                    <tr>
                        <td style="padding: 8px; border-bottom: 1px solid #ddd;">${action}</td>
                        <td style="padding: 8px; text-align: right; border-bottom: 1px solid #ddd;">${count}</td>
                        <td style="padding: 8px; text-align: right; border-bottom: 1px solid #ddd;">${percentage}%</td>
                    </tr>
                `;
            });

        return `
            <div style="text-align: center; margin-bottom: 30px;">
                <h1 style="margin: 0; color: #2c3e50; font-size: 28px; font-weight: bold;">Audit Log Summary</h1>
                <p style="margin: 10px 0 0 0; color: #666; font-size: 16px;">System Activity Report</p>
                <p style="margin: 5px 0 0 0; color: #666; font-size: 14px;">Generated on ${new Date().toLocaleDateString()}</p>
            </div>
            
            <div style="border-bottom: 2px solid #e0e0e0; margin: 30px 0;"></div>
            
            <div style="margin-bottom: 20px;">
                <h3 style="color: #2c3e50; margin-bottom: 10px;">Activity Summary</h3>
                <table style="width: 100%; border-collapse: collapse;">
                    <tr>
                        <td style="padding: 8px; border-bottom: 1px solid #ddd;"><strong>Total Activities:</strong></td>
                        <td style="padding: 8px; text-align: right; border-bottom: 1px solid #ddd;">${totalActivities}</td>
                    </tr>
                    <tr>
                        <td style="padding: 8px; border-bottom: 1px solid #ddd;"><strong>Active Users:</strong></td>
                        <td style="padding: 8px; text-align: right; border-bottom: 1px solid #ddd;">${uniqueUsers}</td>
                    </tr>
                </table>
            </div>
            
            <h3 style="color: #2c3e50; margin-bottom: 10px;">Activities by Type</h3>
            <table style="width: 100%; border-collapse: collapse;">
                <thead>
                    <tr style="background-color: #f8f9fa; font-weight: bold;">
                        <th style="padding: 10px 8px; text-align: left; border-bottom: 2px solid #ddd;">Activity Type</th>
                        <th style="padding: 10px 8px; text-align: right; border-bottom: 2px solid #ddd;">Count</th>
                        <th style="padding: 10px 8px; text-align: right; border-bottom: 2px solid #ddd;">Percentage</th>
                    </tr>
                </thead>
                <tbody>
                    ${actionRows || '<tr><td colspan="3" style="padding: 20px; text-align: center;">No audit logs found</td></tr>'}
                </tbody>
            </table>
        `;
    };

    const handleDownload = async (reportTitle, reportType) => {
        if (isGenerating) return;
        
        setIsGenerating(true);
        
        try {
            const reportContent = generateReportContent(reportType);
            
            // Temporarily add to DOM for rendering
            reportContent.style.position = 'absolute';
            reportContent.style.left = '-9999px';
            document.body.appendChild(reportContent);
            
            const canvas = await html2canvas(reportContent, {
                scale: 2,
                useCORS: true,
                logging: false,
                backgroundColor: '#ffffff',
                width: 800,
                height: reportContent.scrollHeight
            });
            
            // Remove temporary element
            document.body.removeChild(reportContent);
            
            const imgData = canvas.toDataURL('image/png');
            const pdf = new jsPDF('p', 'mm', 'a4');
            const imgWidth = 210; // A4 width in mm
            const pageHeight = 297; // A4 height in mm
            const imgHeight = (canvas.height * imgWidth) / canvas.width;
            let heightLeft = imgHeight;
            let position = 0;
            
            // Add first page
            pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
            heightLeft -= pageHeight;
            
            // Add additional pages if content is longer than one page
            while (heightLeft >= 0) {
                position = heightLeft - imgHeight;
                pdf.addPage();
                pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
                heightLeft -= pageHeight;
            }
            
            // Save the PDF
            const filename = `${reportTitle.toLowerCase().replace(/\s+/g, '-')}-${new Date().toISOString().split('T')[0]}.pdf`;
            pdf.save(filename);
            
        } catch (error) {
            console.error('Error generating PDF:', error);
            alert('Failed to generate PDF. Please try again.');
        } finally {
            setIsGenerating(false);
        }
    };

    // Debug loading states
    useEffect(() => {
        console.log('Reports - loading states debug:', {
            loading: loading,
            reportsLoading: reportsLoading,
            shouldShowLoading: loading || reportsLoading
        });
    }, [loading, reportsLoading]);

    if (reportsLoading) {
        console.log('Reports - showing loading spinner because:', { loading, reportsLoading });
        return (
            <div className="page-loading">
                <div className="loading-spinner"></div>
                <p>Loading reports...</p>
            </div>
        );
    }

    return (
        <div className="reports-page">
            <div className="page-header">
                <h1 className="page-title">Financial Reports</h1>
                <p className="page-description">Generate and download financial statements and system reports</p>
            </div>

            {!currentSeason && (
                <div className="alert alert-warning" style={{ marginBottom: 'var(--spacing-lg)' }}>
                    No active season selected. Reports will show data from all seasons.
                </div>
            )}

            <div className="reports-grid">
                {reports.map((report) => (
                    <div key={report.id} className={`report-card card-accent-${report.accent}`}>
                        <div className="report-main-content">
                            <div className="report-content-wrapper">
                                <div className={`report-icon-wrapper icon-bg-${report.iconBg}`}>
                                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                        <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path>
                                        <polyline points="14 2 14 8 20 8"></polyline>
                                        <line x1="16" y1="13" x2="8" y2="13"></line>
                                        <line x1="16" y1="17" x2="8" y2="17"></line>
                                        <polyline points="10 9 9 9 8 9"></polyline>
                                    </svg>
                                </div>
                                <div className="report-details">
                                    <h3 className={`report-title text-${report.accent === 'brown' ? 'brown-dark' : report.accent}`}>
                                        {report.title}
                                    </h3>
                                    <div className="report-meta">
                                        Generated from backend data
                                    </div>
                                </div>
                            </div>

                            <div className="report-actions">
                                <button
                                    className={`btn-download-pdf btn-outline-${report.accent}`}
                                    onClick={() => handleDownload(report.title, report.type)}
                                    disabled={isGenerating}
                                >
                                    {isGenerating ? 'Generating...' : 'Download PDF'}
                                </button>
                            </div>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default Reports;

import React, { useState, useMemo, useEffect } from 'react';
import { useData } from '../../context/DataContext';
import { seasonsAPI, revenuesAPI } from '../../services/api';
import Modal from '../../components/common/Modal';
import './SeasonManagement.css';

const SeasonManagement = () => {
    const { seasons, revenue, fetchSeasons, fetchRevenues, loading } = useData();
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isUpdateModalOpen, setIsUpdateModalOpen] = useState(false);
    const [editingSeason, setEditingSeason] = useState(null);
    const [hoveredBar, setHoveredBar] = useState(null);
    const [tooltipPosition, setTooltipPosition] = useState({ x: 0, y: 0 });
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState(null);
    const [successMessage, setSuccessMessage] = useState(null);
    const [isConfirmModalOpen, setIsConfirmModalOpen] = useState(false);
    const [seasonToDeactivate, setSeasonToDeactivate] = useState(null);
    const [formData, setFormData] = useState({
        name: '',
        start_date: '',
        end_date: '',
        active: true
    });
    const [updateFormData, setUpdateFormData] = useState({
        name: '',
        start_date: '',
        end_date: '',
        active: false
    });

    // Load revenues on mount to calculate season revenue
    useEffect(() => {
        if (revenue.length === 0) {
            fetchRevenues();
        }
    }, []);

    // Load seasons when component mounts
    useEffect(() => {
        fetchSeasons();
    }, []);

    // Transform backend season to frontend format
    const transformSeason = (season) => {
        // Calculate revenue for this season
        const seasonRevenue = revenue
            .filter(r => r.season_id === season.id)
            .reduce((sum, r) => sum + parseFloat(r.total_amount || 0), 0);

        return {
            id: season.id,
            name: season.name,
            startDate: season.start_date ? new Date(season.start_date).toLocaleDateString() : 'Not set',
            endDate: season.end_date ? new Date(season.end_date).toLocaleDateString() : 'Not set',
            status: season.active ? 'active' : 'closed',
            active: season.active,
            revenue: seasonRevenue
        };
    };

    // Transform seasons with revenue calculations
    const displaySeasons = useMemo(() => {
        return seasons.map(transformSeason);
    }, [seasons, revenue]);

    // Prepare chart data
    const chartData = useMemo(() => {
        return displaySeasons
            .filter(s => s.revenue > 0)
            .sort((a, b) => {
                // Sort by season name (year + letter)
                const aYear = parseInt(a.name.substring(0, 4));
                const bYear = parseInt(b.name.substring(0, 4));
                if (aYear !== bYear) return aYear - bYear;
                return a.name.localeCompare(b.name);
            });
    }, [displaySeasons]);

    const maxRevenue = Math.max(...chartData.map(d => d.revenue), 1);
    // Figma dimensions: 1036x511, proportional scaling
    const chartWidth = 1036;
    const chartHeight = 511;
    const barWidth = 80;
    const spacing = 40;

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError(null);
        setIsSubmitting(true);

        try {
            // Validate dates
            if (new Date(formData.start_date) > new Date(formData.end_date)) {
                setError('End date must be after start date');
                setIsSubmitting(false);
                return;
            }

            await seasonsAPI.create({
                name: formData.name,
                start_date: formData.start_date,
                end_date: formData.end_date,
                active: formData.active
            });

            setIsModalOpen(false);
            setFormData({ name: '', start_date: '', end_date: '', active: true });
            await fetchSeasons();
        } catch (err) {
            console.error('Error creating season:', err);
            setError(err.message || 'Failed to create season. Please try again.');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleUpdateClick = (season) => {
        // Find the original season from backend format
        const originalSeason = seasons.find(s => s.id === season.id);
        if (!originalSeason) return;

        setEditingSeason(originalSeason);
        setUpdateFormData({
            name: originalSeason.name,
            start_date: originalSeason.start_date,
            end_date: originalSeason.end_date,
            active: originalSeason.active
        });
        setIsUpdateModalOpen(true);
    };

    const handleUpdateSubmit = async (e) => {
        e.preventDefault();
        if (!editingSeason) return;

        setError(null);
        setIsSubmitting(true);

        try {
            // Validate dates
            if (new Date(updateFormData.start_date) > new Date(updateFormData.end_date)) {
                setError('End date must be after start date');
                setIsSubmitting(false);
                return;
            }

            await seasonsAPI.update(editingSeason.id, {
                name: updateFormData.name,
                start_date: updateFormData.start_date,
                end_date: updateFormData.end_date,
                active: updateFormData.active
            });

            setIsUpdateModalOpen(false);
            setEditingSeason(null);
            await fetchSeasons();
        } catch (err) {
            console.error('Error updating season:', err);
            setError(err.message || 'Failed to update season. Please try again.');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleDeactivate = async (seasonId) => {
        const season = displaySeasons.find(s => s.id === seasonId);
        if (!season) return;

        setSeasonToDeactivate(season);
        setIsConfirmModalOpen(true);
    };

    const confirmDeactivate = async () => {
        if (!seasonToDeactivate) return;

        setIsConfirmModalOpen(false);
        setError(null);
        setIsSubmitting(true);

        try {
            await seasonsAPI.deactivate(seasonToDeactivate.id);
            setSuccessMessage(`Season "${seasonToDeactivate.name}" has been deactivated successfully.`);
            await fetchSeasons();

            // Clear success message after 5 seconds
            setTimeout(() => setSuccessMessage(null), 5000);
        } catch (err) {
            console.error('Error deactivating season:', err);
            setError(err.message || 'Failed to deactivate season. Please try again.');
        } finally {
            setIsSubmitting(false);
            setSeasonToDeactivate(null);
        }
    };

    const getStatusColor = (status) => {
        return status === 'active' ? '#10B981' : '#EF4444';
    };

    const getBarColor = (index) => {
        const colors = ['#9B59B6', '#FF6B6B', '#3498DB', '#FF9800', '#3498DB', '#10B981', '#9B59B6', '#3498DB'];
        return colors[index % colors.length];
    };

    return (
        <div className="season-management">
            <div className="page-header">
                <h1 className="page-title">Season Management</h1>
                <p className="page-description">Manage coffee harvesting season</p>
            </div>

            <div className="chart-card">
                <h3 className="chart-title">Revenue Per Season</h3>
                <div className="bar-chart-container">
                    <svg viewBox={`0 0 ${chartWidth} ${chartHeight + 60}`} className="bar-chart" preserveAspectRatio="xMidYMid meet">
                        {/* Y-axis label */}
                        <text x="20" y={chartHeight / 2} fontSize="12" fill="#666" transform={`rotate(-90, 20, ${chartHeight / 2})`} textAnchor="middle">
                            Revenue/RWF
                        </text>

                        {/* Y-axis values */}
                        {[0, 2, 4, 6, 8, 10, 12].map((val) => {
                            const y = chartHeight - (val / 12) * chartHeight;
                            return (
                                <g key={val}>
                                    <line x1="50" y1={y} x2={chartWidth - 20} y2={y} stroke="#e5e7eb" strokeWidth="1" strokeDasharray="2,2" />
                                    <text x="45" y={y + 4} fontSize="10" fill="#666" textAnchor="end">
                                        {val}M
                                    </text>
                                </g>
                            );
                        })}

                        {/* Bars */}
                        {chartData.map((season, index) => {
                            const barHeight = (season.revenue / maxRevenue) * chartHeight;
                            const x = 60 + index * (barWidth + spacing);
                            const y = chartHeight - barHeight;
                            const color = getBarColor(index);

                            return (
                                <g key={season.id}>
                                    <rect
                                        x={x}
                                        y={y}
                                        width={barWidth}
                                        height={barHeight}
                                        fill={color}
                                        rx="4"
                                        style={{ cursor: 'pointer' }}
                                        onMouseEnter={(e) => {
                                            const container = e.currentTarget.closest('.bar-chart-container');
                                            const containerRect = container.getBoundingClientRect();
                                            const svgRect = e.currentTarget.closest('svg').getBoundingClientRect();
                                            const scaleX = containerRect.width / chartWidth;
                                            const scaleY = containerRect.height / (chartHeight + 60);
                                            setHoveredBar({
                                                name: season.name,
                                                revenue: season.revenue
                                            });
                                            setTooltipPosition({
                                                x: (x + barWidth / 2) * scaleX,
                                                y: y * scaleY - 10
                                            });
                                        }}
                                        onMouseLeave={() => setHoveredBar(null)}
                                    />
                                    <text
                                        x={x + barWidth / 2}
                                        y={y - 5}
                                        fontSize="10"
                                        fill="#666"
                                        textAnchor="middle"
                                    >
                                        {(season.revenue / 1000000).toFixed(1)}M
                                    </text>
                                    <text
                                        x={x + barWidth / 2}
                                        y={chartHeight + 20}
                                        fontSize="10"
                                        fill="#666"
                                        textAnchor="middle"
                                    >
                                        {season.name}
                                    </text>
                                </g>
                            );
                        })}

                        {/* X-axis label */}
                        <text x={chartWidth / 2} y={chartHeight + 50} fontSize="12" fill="#666" textAnchor="middle">
                            Seasons
                        </text>
                    </svg>
                    {hoveredBar && (
                        <div
                            className="chart-tooltip"
                            style={{
                                left: `${tooltipPosition.x}px`,
                                top: `${tooltipPosition.y}px`,
                            }}
                        >
                            <div className="tooltip-content">
                                <div className="tooltip-label">{hoveredBar.name}</div>
                                <div className="tooltip-value">{hoveredBar.revenue.toLocaleString()} RWF</div>
                            </div>
                        </div>
                    )}
                </div>
            </div>

            <div className="content-card">
                <div className="card-header-section">
                    <h2 className="section-title">All Seasons</h2>
                    <button onClick={() => setIsModalOpen(true)} className="btn-add-season" disabled={isSubmitting}>
                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                            <line x1="12" y1="5" x2="12" y2="19"></line>
                            <line x1="5" y1="12" x2="19" y2="12"></line>
                        </svg>
                        Add Season
                    </button>
                </div>

                {error && (
                    <div className="alert alert-error" style={{ marginBottom: 'var(--spacing-md)' }}>
                        {error}
                    </div>
                )}

                {successMessage && (
                    <div className="alert alert-success" style={{ marginBottom: 'var(--spacing-md)' }}>
                        {successMessage}
                    </div>
                )}

                {loading.seasons ? (
                    <div style={{ padding: '2rem', textAlign: 'center' }}>Loading seasons...</div>
                ) : displaySeasons.length === 0 ? (
                    <div style={{ padding: '2rem', textAlign: 'center' }}>No seasons found. Create your first season to get started.</div>
                ) : (
                    <div className="table-container">
                        <table className="seasons-table">
                            <thead>
                                <tr>
                                    <th>SEASON NAME</th>
                                    <th>START DATE</th>
                                    <th>END DATE</th>
                                    <th>STATUS</th>
                                    <th>REVENUE</th>
                                    <th>ACTIONS</th>
                                </tr>
                            </thead>
                            <tbody>
                                {displaySeasons.map(season => (
                                    <tr key={season.id}>
                                        <td>
                                            <span className="season-name-link">{season.name}</span>
                                        </td>
                                        <td>{season.startDate}</td>
                                        <td>{season.endDate}</td>
                                        <td>
                                            <span
                                                className={`badge ${season.status === 'active' ? 'badge-status-active' : 'badge-status-closed'}`}
                                            >
                                                {season.status === 'active' ? 'Active' : 'Closed'}
                                            </span>
                                        </td>
                                        <td>RWF {season.revenue.toLocaleString()}</td>
                                        <td>
                                            <div style={{ display: 'flex', gap: '0.5rem' }}>
                                                <button 
                                                    className="btn-update"
                                                    onClick={() => handleUpdateClick(season)}
                                                    disabled={isSubmitting}
                                                >
                                                    Update
                                                </button>
                                                {season.active && (
                                                    <button 
                                                        className="btn btn-outline"
                                                        onClick={() => handleDeactivate(season.id)}
                                                        disabled={isSubmitting}
                                                        style={{ fontSize: '0.875rem', padding: '0.25rem 0.5rem' }}
                                                    >
                                                        Deactivate
                                                    </button>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="Create New Season">
                {error && (
                    <div className="alert alert-error" style={{ marginBottom: 'var(--spacing-md)' }}>
                        {error}
                    </div>
                )}
                <form onSubmit={handleSubmit}>
                    <div className="form-group">
                        <label className="form-label required">Season Name</label>
                        <input
                            type="text"
                            className="form-input"
                            value={formData.name}
                            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                            placeholder="e.g., 2025B"
                            required
                            disabled={isSubmitting}
                        />
                    </div>

                    <div className="form-group">
                        <label className="form-label required">Start Date</label>
                        <input
                            type="date"
                            className="form-input"
                            value={formData.start_date}
                            onChange={(e) => setFormData({ ...formData, start_date: e.target.value })}
                            required
                            disabled={isSubmitting}
                        />
                    </div>

                    <div className="form-group">
                        <label className="form-label required">End Date</label>
                        <input
                            type="date"
                            className="form-input"
                            value={formData.end_date}
                            onChange={(e) => setFormData({ ...formData, end_date: e.target.value })}
                            required
                            disabled={isSubmitting}
                        />
                    </div>

                    <div className="form-group">
                        <label className="form-label">Active Status</label>
                        <select
                            className="form-select"
                            value={formData.active ? 'true' : 'false'}
                            onChange={(e) => setFormData({ ...formData, active: e.target.value === 'true' })}
                            disabled={isSubmitting}
                        >
                            <option value="true">Active</option>
                            <option value="false">Inactive</option>
                        </select>
                        <small style={{ color: 'var(--color-gray-600)', fontSize: '0.875rem' }}>
                            Only one season should be active at a time
                        </small>
                    </div>

                    <div className="actions-group" style={{ marginTop: 'var(--spacing-lg)' }}>
                        <button type="submit" className="btn btn-primary" disabled={isSubmitting}>
                            {isSubmitting ? 'Creating...' : 'Create Season'}
                        </button>
                        <button type="button" onClick={() => setIsModalOpen(false)} className="btn btn-outline" disabled={isSubmitting}>
                            Cancel
                        </button>
                    </div>
                </form>
            </Modal>

            <Modal isOpen={isUpdateModalOpen} onClose={() => setIsUpdateModalOpen(false)} title="Update Season">
                {error && (
                    <div className="alert alert-error" style={{ marginBottom: 'var(--spacing-md)' }}>
                        {error}
                    </div>
                )}
                <form onSubmit={handleUpdateSubmit}>
                    <div className="form-group">
                        <label className="form-label required">Season Name</label>
                        <input
                            type="text"
                            className="form-input"
                            value={updateFormData.name}
                            onChange={(e) => setUpdateFormData({ ...updateFormData, name: e.target.value })}
                            required
                            disabled={isSubmitting}
                        />
                    </div>

                    <div className="form-group">
                        <label className="form-label required">Start Date</label>
                        <input
                            type="date"
                            className="form-input"
                            value={updateFormData.start_date}
                            onChange={(e) => setUpdateFormData({ ...updateFormData, start_date: e.target.value })}
                            required
                            disabled={isSubmitting}
                        />
                    </div>

                    <div className="form-group">
                        <label className="form-label required">End Date</label>
                        <input
                            type="date"
                            className="form-input"
                            value={updateFormData.end_date}
                            onChange={(e) => setUpdateFormData({ ...updateFormData, end_date: e.target.value })}
                            required
                            disabled={isSubmitting}
                        />
                    </div>

                    <div className="form-group">
                        <label className="form-label required">Active Status</label>
                        <select
                            className="form-select"
                            value={updateFormData.active ? 'true' : 'false'}
                            onChange={(e) => setUpdateFormData({ ...updateFormData, active: e.target.value === 'true' })}
                            required
                            disabled={isSubmitting}
                        >
                            <option value="true">Active</option>
                            <option value="false">Inactive</option>
                        </select>
                        <small style={{ color: 'var(--color-gray-600)', fontSize: '0.875rem' }}>
                            Only one season should be active at a time
                        </small>
                    </div>

                    <div className="actions-group" style={{ marginTop: 'var(--spacing-lg)' }}>
                        <button type="submit" className="btn btn-primary" disabled={isSubmitting}>
                            {isSubmitting ? 'Updating...' : 'Update Season'}
                        </button>
                        <button type="button" onClick={() => setIsUpdateModalOpen(false)} className="btn btn-outline" disabled={isSubmitting}>
                            Cancel
                        </button>
                    </div>
                </form>
            </Modal>

            <Modal 
                isOpen={isConfirmModalOpen} 
                onClose={() => {
                    setIsConfirmModalOpen(false);
                    setSeasonToDeactivate(null);
                }} 
                title="Confirm Deactivation"
            >
                <div style={{ padding: 'var(--spacing-md) 0' }}>
                    <p style={{ marginBottom: 'var(--spacing-md)', fontSize: '1rem' }}>
                        Are you sure you want to deactivate the season <strong>"{seasonToDeactivate?.name}"</strong>?
                    </p>
                    <div style={{ 
                        backgroundColor: '#fef3c7', 
                        border: '1px solid #f59e0b', 
                        borderRadius: '6px', 
                        padding: 'var(--spacing-sm)',
                        marginBottom: 'var(--spacing-lg)'
                    }}>
                        <p style={{ margin: 0, fontSize: '0.875rem', color: '#92400e' }}>
                            <strong>Note:</strong> Deactivating this season will prevent new deliveries from being assigned to it. 
                            Existing deliveries and records will remain unchanged.
                        </p>
                    </div>
                </div>

                <div className="actions-group" style={{ display: 'flex', gap: 'var(--spacing-sm)', justifyContent: 'flex-end' }}>
                    <button 
                        type="button" 
                        onClick={() => {
                            setIsConfirmModalOpen(false);
                            setSeasonToDeactivate(null);
                        }} 
                        className="btn btn-outline" 
                        disabled={isSubmitting}
                    >
                        Cancel
                    </button>
                    <button 
                        type="button" 
                        onClick={confirmDeactivate} 
                        className="btn btn-danger" 
                        disabled={isSubmitting}
                        style={{ backgroundColor: '#dc2626', borderColor: '#dc2626' }}
                    >
                        {isSubmitting ? 'Deactivating...' : 'Deactivate Season'}
                    </button>
                </div>
            </Modal>
        </div>
    );
};

export default SeasonManagement;

import React, { useState, useMemo, useEffect } from 'react';
import { useData } from '../../context/DataContext';
import { adminUsersAPI, authAPI, farmersAPI } from '../../services/api';
import Modal from '../../components/common/Modal';
import './UserManagement.css';

const UserManagement = () => {
    const { loading } = useData();
    const [users, setUsers] = useState([]);
    const [farmers, setFarmers] = useState([]);
    const [isLoading, setIsLoading] = useState(false);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isUpdateModalOpen, setIsUpdateModalOpen] = useState(false);
    const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
    const [editingUser, setEditingUser] = useState(null);
    const [deletingUser, setDeletingUser] = useState(null);
    const [filterRole, setFilterRole] = useState('all');
    const [error, setError] = useState(null);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        password: '',
        role: 'RECEPTIONIST'
    });
    const [updateFormData, setUpdateFormData] = useState({
        name: '',
        email: '',
        role: 'RECEPTIONIST'
    });

    // Fetch users and farmers on mount
    useEffect(() => {
        fetchUsers();
        fetchFarmers();
    }, []);

    const fetchUsers = async () => {
        setIsLoading(true);
        setError(null);
        try {
            const response = await adminUsersAPI.getAll();
            console.log('Users API response:', response);

            // Handle different response structures
            const usersData = response?.data?.data || response?.data || [];

            if (!Array.isArray(usersData)) {
                console.error('Users data is not an array:', usersData);
                setError('Invalid users data format');
                setUsers([]);
                return;
            }

            setUsers(usersData);
        } catch (err) {
            console.error('Error fetching users:', err);
            setError(err.message || 'Failed to fetch users. Please try again.');
        } finally {
            setIsLoading(false);
        }
    };

    const fetchFarmers = async () => {
        setIsLoading(true);
        setError(null);
        try {
            const response = await farmersAPI.getAll();
            console.log('Farmers API response:', response);

            // Handle different response structures
            const farmersData = response?.data?.data || response?.data || [];

            if (!Array.isArray(farmersData)) {
                console.error('Farmers data is not an array:', farmersData);
                setError('Invalid farmers data format');
                setFarmers([]);
                return;
            }

            setFarmers(farmersData);
        } catch (err) {
            console.error('Error fetching farmers:', err);
            setError(err.message || 'Failed to fetch farmers. Please try again.');
        } finally {
            setIsLoading(false);
        }
    };

    // Filter users
    const displayUsers = useMemo(() => {
        let filtered = [...users];

        console.log('Filtering users:', { totalUsers: users.length, filterRole, users });

        if (filterRole !== 'all') {
            filtered = filtered.filter(u => {
                const matches = u.role === filterRole;
                console.log(`User ${u.name} (${u.role}) matches filter (${filterRole}):`, matches);
                return matches;
            });
        }

        console.log('Filtered users:', filtered.length);
        return filtered;
    }, [users, filterRole]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError(null);
        setIsSubmitting(true);

        try {
            // Map frontend role to backend ENUM
            const roleMap = {
                'receptionist': 'RECEPTIONIST',
                'operator': 'OPERATOR',
                'finance': 'FINANCE',
                'admin': 'ADMIN'
            };

            await authAPI.register({
                name: formData.name,
                email: formData.email,
                password: formData.password,
                role: roleMap[formData.role] || 'RECEPTIONIST'
            });

            setIsModalOpen(false);
            setFormData({ name: '', email: '', password: '', role: 'RECEPTIONIST' });
            await fetchUsers();
        } catch (err) {
            console.error('Error creating user:', err);
            setError(err.message || 'Failed to create user. Please try again.');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleUpdateClick = (user) => {
        setEditingUser(user);
        // Map role back to uppercase for backend
        const roleMap = {
            'receptionist': 'RECEPTIONIST',
            'operator': 'OPERATOR',
            'finance': 'FINANCE',
            'admin': 'ADMIN'
        };
        setUpdateFormData({
            name: user.name,
            email: user.email,
            role: roleMap[user.role] || 'RECEPTIONIST'
        });
        setIsUpdateModalOpen(true);
    };

    const handleUpdateSubmit = async (e) => {
        e.preventDefault();
        if (!editingUser) return;

        setError(null);
        setIsSubmitting(true);

        try {
            await adminUsersAPI.update(editingUser.id, {
                name: updateFormData.name,
                email: updateFormData.email,
                role: updateFormData.role
            });

            setIsUpdateModalOpen(false);
            setEditingUser(null);
            await fetchUsers();
        } catch (err) {
            console.error('Error updating user:', err);
            setError(err.message || 'Failed to update user. Please try again.');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleDeleteClick = (user) => {
        setDeletingUser(user);
        setIsDeleteModalOpen(true);
    };

    const handleDeleteConfirm = async () => {
        if (!deletingUser) return;

        setIsSubmitting(true);
        try {
            await adminUsersAPI.delete(deletingUser.id);
            setIsDeleteModalOpen(false);
            setDeletingUser(null);
            await fetchUsers();
        } catch (err) {
            console.error('Error deleting user:', err);
            alert(err.message || 'Failed to delete user. Please try again.');
        } finally {
            setIsSubmitting(false);
        }
    };

    const getRoleDisplay = (role) => {
        const roleMap = {
            admin: 'Admin',
            receptionist: 'Receptionist',
            operator: 'Operator',
            finance: 'Finance',
            sustainability: 'Sustainability'
        };
        return roleMap[role?.toLowerCase()] || role;
    };

    const getRoleValue = (role) => {
        const roleMap = {
            'RECEPTIONIST': 'receptionist',
            'OPERATOR': 'operator',
            'FINANCE': 'finance',
            'ADMIN': 'admin'
        };
        return roleMap[role] || role?.toLowerCase() || 'receptionist';
    };

    return (
        <div className="user-management">
            <div className="page-header">
                <h1 className="page-title">User management</h1>
                <p className="page-description">Manage users and their access roles</p>
            </div>

            <div className="content-card">
                <div className="card-header-section">
                    <h2 className="section-title">All users</h2>
                    <button onClick={() => setIsModalOpen(true)} className="btn-add-user">
                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                            <line x1="12" y1="5" x2="12" y2="19"></line>
                            <line x1="5" y1="12" x2="19" y2="12"></line>
                        </svg>
                        Add user
                    </button>
                </div>

                {error && (
                    <div className="alert alert-error" style={{ marginBottom: 'var(--spacing-md)' }}>
                        {error}
                    </div>
                )}

                <div className="filters-section">
                    <div className="filter-group">
                        <label className="filter-label">Filter by Role:</label>
                        <select
                            className="filter-select"
                            value={filterRole}
                            onChange={(e) => setFilterRole(e.target.value)}
                        >
                            <option value="all">All Roles</option>
                            <option value="admin">Admin</option>
                            <option value="receptionist">Receptionist</option>
                            <option value="operator">Operator</option>
                            <option value="finance">Financial</option>
                        </select>
                    </div>
                </div>

                {isLoading ? (
                    <div style={{ padding: '2rem', textAlign: 'center' }}>Loading users...</div>
                ) : error ? (
                    <div style={{ padding: '2rem', textAlign: 'center', color: 'var(--color-error)' }}>
                        Error: {error}
                        <br />
                        <button onClick={fetchUsers} className="btn btn-outline" style={{ marginTop: '1rem' }}>
                            Retry
                        </button>
                    </div>
                ) : displayUsers.length === 0 ? (
                    <div style={{ padding: '2rem', textAlign: 'center' }}>
                        No users found.
                        {users.length === 0 && (
                            <div style={{ marginTop: '0.5rem', fontSize: '0.875rem', color: 'var(--color-gray-600)' }}>
                                (Total users: {users.length})
                            </div>
                        )}
                    </div>
                ) : (
                    <div className="table-container">
                        <table className="users-table">
                            <thead>
                                <tr>
                                    <th>Names</th>
                                    <th>Email</th>
                                    <th>Role</th>
                                    <th>Status</th>
                                    <th>Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {displayUsers.map(user => (
                                    <tr key={user.id}>
                                        <td><strong>{user.name}</strong></td>
                                        <td>{user.email}</td>
                                        <td>
                                            <span className={`badge ${user.role === 'admin' ? 'badge-role-admin' : 'badge-role-other'}`}>
                                                {getRoleDisplay(user.role)}
                                            </span>
                                        </td>
                                        <td>
                                            <span className="badge badge-status-active">
                                                Active
                                            </span>
                                        </td>
                                        <td>
                                            <div style={{ display: 'flex', gap: '0.5rem' }}>
                                                <button 
                                                    className="btn-update"
                                                    onClick={() => handleUpdateClick(user)}
                                                    disabled={isSubmitting}
                                                >
                                                    Update
                                                </button>
                                                <button 
                                                    className="btn btn-outline"
                                                    onClick={() => handleDeleteClick(user)}
                                                    disabled={isSubmitting}
                                                    style={{ fontSize: '0.875rem', padding: '0.25rem 0.5rem', color: 'var(--color-error)' }}
                                                >
                                                    Delete
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="Add New User">
                {error && (
                    <div className="alert alert-error" style={{ marginBottom: 'var(--spacing-md)' }}>
                        {error}
                    </div>
                )}
                <form onSubmit={handleSubmit}>
                    <div className="form-group">
                        <label className="form-label required">Name</label>
                        <input
                            type="text"
                            className="form-input"
                            value={formData.name}
                            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                            required
                            disabled={isSubmitting}
                        />
                    </div>

                    <div className="form-group">
                        <label className="form-label required">Email</label>
                        <input
                            type="email"
                            className="form-input"
                            value={formData.email}
                            onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                            required
                            disabled={isSubmitting}
                        />
                    </div>

                    <div className="form-group">
                        <label className="form-label required">Password</label>
                        <input
                            type="password"
                            className="form-input"
                            value={formData.password}
                            onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                            required
                            disabled={isSubmitting}
                            minLength={6}
                        />
                        <small style={{ color: 'var(--color-gray-600)', fontSize: '0.875rem' }}>
                            Minimum 6 characters
                        </small>
                    </div>

                    <div className="form-group">
                        <label className="form-label required">Role</label>
                        <select
                            className="form-select"
                            value={formData.role}
                            onChange={(e) => setFormData({ ...formData, role: e.target.value })}
                            required
                            disabled={isSubmitting}
                        >
                            <option value="RECEPTIONIST">Receptionist</option>
                            <option value="OPERATOR">Operator</option>
                            <option value="FINANCE">Finance</option>
                            <option value="ADMIN">Admin</option>
                        </select>
                    </div>

                    <div className="actions-group" style={{ marginTop: 'var(--spacing-lg)' }}>
                        <button type="submit" className="btn btn-primary" disabled={isSubmitting}>
                            {isSubmitting ? 'Creating...' : 'Create User'}
                        </button>
                        <button type="button" onClick={() => setIsModalOpen(false)} className="btn btn-outline" disabled={isSubmitting}>
                            Cancel
                        </button>
                    </div>
                </form>
            </Modal>

            <Modal isOpen={isUpdateModalOpen} onClose={() => setIsUpdateModalOpen(false)} title="Update User">
                {error && (
                    <div className="alert alert-error" style={{ marginBottom: 'var(--spacing-md)' }}>
                        {error}
                    </div>
                )}
                <form onSubmit={handleUpdateSubmit}>
                    <div className="form-group">
                        <label className="form-label required">Name</label>
                        <input
                            type="text"
                            className="form-input"
                            value={updateFormData.name}
                            onChange={(e) => setUpdateFormData({ ...updateFormData, name: e.target.value })}
                            required
                            disabled={isSubmitting}
                        />
                    </div>

                    <div className="form-group">
                        <label className="form-label required">Email</label>
                        <input
                            type="email"
                            className="form-input"
                            value={updateFormData.email}
                            onChange={(e) => setUpdateFormData({ ...updateFormData, email: e.target.value })}
                            required
                            disabled={isSubmitting}
                        />
                    </div>

                    <div className="form-group">
                        <label className="form-label required">Role</label>
                        <select
                            className="form-select"
                            value={updateFormData.role}
                            onChange={(e) => setUpdateFormData({ ...updateFormData, role: e.target.value })}
                            required
                            disabled={isSubmitting}
                        >
                            <option value="RECEPTIONIST">Receptionist</option>
                            <option value="OPERATOR">Operator</option>
                            <option value="FINANCE">Finance</option>
                            <option value="ADMIN">Admin</option>
                        </select>
                    </div>

                    <div className="actions-group" style={{ marginTop: 'var(--spacing-lg)' }}>
                        <button type="submit" className="btn btn-primary" disabled={isSubmitting}>
                            {isSubmitting ? 'Updating...' : 'Update User'}
                        </button>
                        <button type="button" onClick={() => setIsUpdateModalOpen(false)} className="btn btn-outline" disabled={isSubmitting}>
                            Cancel
                        </button>
                    </div>
                </form>
            </Modal>

            <Modal isOpen={isDeleteModalOpen} onClose={() => setIsDeleteModalOpen(false)} title="Delete User">
                {deletingUser && (
                    <div>
                        <p>Are you sure you want to delete user <strong>{deletingUser.name}</strong> ({deletingUser.email})?</p>
                        <p style={{ color: 'var(--color-error)', marginTop: 'var(--spacing-md)' }}>
                            This action cannot be undone.
                        </p>
                        <div className="actions-group" style={{ marginTop: 'var(--spacing-lg)' }}>
                            <button onClick={handleDeleteConfirm} className="btn btn-primary" disabled={isSubmitting} style={{ backgroundColor: 'var(--color-error)' }}>
                                {isSubmitting ? 'Deleting...' : 'Delete User'}
                            </button>
                            <button onClick={() => setIsDeleteModalOpen(false)} className="btn btn-outline" disabled={isSubmitting}>
                                Cancel
                            </button>
                        </div>
                    </div>
                )}
            </Modal>
        </div>
    );
};

