import React, { useState, useEffect } from 'react';
import { useData } from '../../context/DataContext';
import { laborLogsAPI, workersAPI } from '../../services/api';

const LaborCosts = () => {
    const { laborCosts, fetchLaborLogs, loading } = useData();
    const [workers, setWorkers] = useState([]);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState(null);
    const [formData, setFormData] = useState({
        worker_id: '',
        work_date: new Date().toISOString().split('T')[0],
        hours: '',
        rate: '2500',
        task: '',
    });

    // Load workers on mount
    useEffect(() => {
        loadWorkers();
    }, []);

    const loadWorkers = async () => {
        try {
            const response = await workersAPI.getAll();
            setWorkers(response.data.data.filter(w => w.active !== false));
        } catch (error) {
            console.error('Error loading workers:', error);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError(null);
        setIsSubmitting(true);

        try {
            if (!formData.worker_id) {
                setError('Please select a worker');
                setIsSubmitting(false);
                return;
            }

            const hours = parseFloat(formData.hours);
            const rate = parseFloat(formData.rate);
            const totalAmount = hours * rate;

            await laborLogsAPI.create({
                worker_id: formData.worker_id,
                work_date: formData.work_date,
                total_amount: totalAmount
            });

            alert(`Labor log recorded. Total: RWF ${totalAmount.toLocaleString()}`);
            setFormData({ worker_id: '', work_date: new Date().toISOString().split('T')[0], hours: '', rate: '2500', task: '' });
            await fetchLaborLogs();
        } catch (err) {
            console.error('Error creating labor log:', err);
            setError(err.message || 'Failed to record labor. Please try again.');
        } finally {
            setIsSubmitting(false);
        }
    };

    // Transform labor logs for display
    const transformLaborLog = (log, worker) => ({
        id: log.id,
        date: log.work_date || log.date,
        workerName: worker?.name || 'Unknown',
        workerType: worker?.worker_type?.toLowerCase() || 'N/A',
        hours: 0, // Not stored in backend
        rate: 0, // Not stored in backend
        totalCost: parseFloat(log.total_amount || 0),
        task: formData.task || 'N/A', // Not stored in backend
    });

    const totalLabor = laborCosts.reduce((sum, l) => sum + parseFloat(l.total_amount || 0), 0);

    return (
        <div>
            <div className="page-header">
                <h1 className="page-title">Labor Cost Management</h1>
                <p className="page-description">Track worker attendance and wages</p>
            </div>

            <div className="stats-grid" style={{ marginBottom: 'var(--spacing-xl)' }}>
                <div className="stat-card">
                    <div className="stat-label">Total Labor Costs</div>
                    <div className="stat-value">RWF {totalLabor.toLocaleString()}</div>
                </div>
                <div className="stat-card">
                    <div className="stat-label">Total Records</div>
                    <div className="stat-value">{laborCosts.length}</div>
                </div>
            </div>

            <div className="content-card" style={{ marginBottom: 'var(--spacing-xl)' }}>
                <div className="card-header">
                    <h2 className="card-title">Record Labor</h2>
                </div>

                {error && (
                    <div className="alert alert-error" style={{ marginBottom: 'var(--spacing-md)' }}>
                        {error}
                    </div>
                )}

                <form onSubmit={handleSubmit}>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--spacing-md)' }}>
                        <div className="form-group">
                            <label className="form-label required">Select Worker</label>
                            <select
                                className="form-select"
                                value={formData.worker_id}
                                onChange={(e) => setFormData({ ...formData, worker_id: e.target.value })}
                                required
                                disabled={isSubmitting}
                            >
                                <option value="">-- Select Worker --</option>
                                {workers.map(worker => (
                                    <option key={worker.id} value={worker.id}>
                                        {worker.name} ({worker.worker_type})
                                    </option>
                                ))}
                            </select>
                        </div>

                        <div className="form-group">
                            <label className="form-label required">Work Date</label>
                            <input
                                type="date"
                                className="form-input"
                                value={formData.work_date}
                                onChange={(e) => setFormData({ ...formData, work_date: e.target.value })}
                                required
                                disabled={isSubmitting}
                            />
                        </div>

                        <div className="form-group">
                            <label className="form-label required">Hours Worked</label>
                            <input
                                type="number"
                                className="form-input"
                                value={formData.hours}
                                onChange={(e) => setFormData({ ...formData, hours: e.target.value })}
                                step="0.5"
                                required
                            />
                        </div>

                        <div className="form-group">
                            <label className="form-label required">Rate (RWF/hour)</label>
                            <input
                                type="number"
                                className="form-input"
                                value={formData.rate}
                                onChange={(e) => setFormData({ ...formData, rate: e.target.value })}
                                required
                            />
                        </div>

                        <div className="form-group">
                            <label className="form-label">Task Description (Optional)</label>
                            <input
                                type="text"
                                className="form-input"
                                value={formData.task}
                                onChange={(e) => setFormData({ ...formData, task: e.target.value })}
                                disabled={isSubmitting}
                            />
                        </div>

                        {formData.hours && formData.rate && (
                            <div className="form-group">
                                <label className="form-label">Total Cost</label>
                                <input
                                    type="text"
                                    className="form-input"
                                    value={`RWF ${(parseFloat(formData.hours) * parseFloat(formData.rate)).toLocaleString()}`}
                                    disabled
                                    style={{ backgroundColor: 'var(--color-gray-100)', fontWeight: 'bold' }}
                                />
                            </div>
                        )}
                    </div>

                    <button type="submit" className="btn btn-primary" disabled={isSubmitting}>
                        {isSubmitting ? 'Recording...' : 'Record Labor'}
                    </button>
                </form>
            </div>

            <div className="content-card">
                <div className="card-header">
                    <h2 className="card-title">Labor Records</h2>
                </div>

                {loading.laborCosts ? (
                    <div style={{ padding: '2rem', textAlign: 'center' }}>Loading labor records...</div>
                ) : laborCosts.length === 0 ? (
                    <div style={{ padding: '2rem', textAlign: 'center' }}>No labor records found.</div>
                ) : (
                    <div className="table-container">
                        <table className="table">
                            <thead>
                                <tr>
                                    <th>Date</th>
                                    <th>Worker ID</th>
                                    <th>Total Cost</th>
                                </tr>
                            </thead>
                            <tbody>
                                {laborCosts.slice().reverse().map(labor => {
                                    const worker = workers.find(w => w.id === labor.worker_id);
                                    return (
                                        <tr key={labor.id}>
                                            <td>{labor.work_date || labor.date}</td>
                                            <td><strong>{worker?.name || labor.worker_id}</strong></td>
                                            <td><strong>RWF {parseFloat(labor.total_amount || 0).toLocaleString()}</strong></td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>
        </div>
    );
};

export default LaborCosts;

import React, { useState, useEffect } from 'react';
import { useData } from '../../context/DataContext';
import { storageAPI } from '../../services/api';
import Modal from '../../components/common/Modal';

const BagManagement = () => {
    const { lots, bags, fetchStorageBags, loading, fetchLots } = useData();
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState(null);
    const [formData, setFormData] = useState({
        lot_id: '',
        bag_code: '',
        weight_kg: '',
        moisture: '',
    });

    // Fetch lots when component loads
    useEffect(() => {
        fetchLots();
        console.log('BagManagement - fetching lots...');
    }, []);

    // Debug logging
    useEffect(() => {
        console.log('BagManagement - lots:', lots);
        console.log('BagManagement - loading:', loading);
    }, [lots, loading]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError(null);
        setIsSubmitting(true);

        try {
            if (!formData.bag_code) {
                setError('Bag code is required');
                setIsSubmitting(false);
                return;
            }

            await storageAPI.create({
                lot_id: formData.lot_id,
                bag_code: formData.bag_code,
                weight_kg: parseFloat(formData.weight_kg),
                moisture: formData.moisture ? parseFloat(formData.moisture) : null,
                stored_at: new Date().toISOString(),
                dispatched: false
            });

            setIsModalOpen(false);
            setFormData({ lot_id: '', bag_code: '', weight_kg: '', moisture: '' });
            await fetchStorageBags();
            await fetchLots(); // Refresh lots data
        } catch (err) {
            console.error('Error creating storage bag:', err);
            setError(err.message || 'Failed to create storage bag. Please try again.');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleDispatch = async (bagId) => {
        try {
            await storageAPI.update(bagId, { dispatched: true });
            await fetchStorageBags();
        } catch (err) {
            console.error('Error updating bag:', err);
            alert(err.message || 'Failed to mark bag as dispatched.');
        }
    };

    // Transform bags for display
    const transformBag = (bag) => {
        const lot = lots.find(l => l.id === bag.lot_id);
        return {
            id: bag.id,
            bagId: bag.bag_code || bag.id,
            lotId: bag.lot_id,
            lotName: lot ? (lot.lotName || lot.id) : bag.lot_id,
            weight: parseFloat(bag.weight_kg || 0),
            moisture: bag.moisture ? parseFloat(bag.moisture) : null,
            storedDate: bag.stored_at?.split('T')[0] || new Date().toISOString().split('T')[0],
            dispatched: bag.dispatched || false,
        };
    };

    const availableBags = bags
        .map(transformBag)
        .filter(b => !b.dispatched)
        .sort((a, b) => new Date(a.storedDate) - new Date(b.storedDate));

    return (
        <div>
            <div className="page-header">
                <h1 className="page-title">Bag Management</h1>
                <p className="page-description">Storage tracking and FIFO dispatch</p>
            </div>

            <div className="content-card" style={{ marginBottom: 'var(--spacing-xl)' }}>
                <div className="card-header">
                    <h2 className="card-title">Available Bags (FIFO Order)</h2>
                    <button onClick={() => setIsModalOpen(true)} className="btn btn-primary">
                        + Add New Bag
                    </button>
                </div>

                {loading.bags ? (
                    <div style={{ padding: '2rem', textAlign: 'center' }}>Loading bags...</div>
                ) : availableBags.length === 0 ? (
                    <div style={{ padding: '2rem', textAlign: 'center' }}>No available bags. All bags have been dispatched.</div>
                ) : (
                    <div className="table-container">
                        <table className="table">
                            <thead>
                                <tr>
                                    <th>Bag Code</th>
                                    <th>Lot Name</th>
                                    <th>Weight (kg)</th>
                                    <th>Moisture (%)</th>
                                    <th>Stored Date</th>
                                    <th>Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {availableBags.map((bag, index) => (
                                    <tr key={bag.id} style={index === 0 ? { backgroundColor: 'rgba(76, 175, 80, 0.1)' } : {}}>
                                        <td>
                                            <strong>{bag.bagId}</strong>
                                            {index === 0 && <span className="badge badge-success" style={{ marginLeft: '0.5rem' }}>Next to dispatch</span>}
                                        </td>
                                        <td>
                                            <strong>{bag.lotName}</strong>
                                        </td>
                                        <td>{bag.weight.toFixed(2)}</td>
                                        <td>{bag.moisture !== null ? `${bag.moisture.toFixed(1)}%` : 'N/A'}</td>
                                        <td>{bag.storedDate}</td>
                                        <td>
                                            <button
                                                onClick={() => handleDispatch(bag.id)}
                                                className="btn btn-accent"
                                                style={{ fontSize: '0.75rem', padding: '0.375rem 0.75rem' }}
                                            >
                                                Mark Dispatched
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="Add New Bag">
                {error && (
                    <div className="alert alert-error" style={{ marginBottom: 'var(--spacing-md)' }}>
                        {error}
                    </div>
                )}
                <form onSubmit={handleSubmit}>
                    <div className="form-group">
                        <label className="form-label required">Lot</label>
                        <select
                            className="form-select"
                            value={formData.lot_id}
                            onChange={(e) => setFormData({ ...formData, lot_id: e.target.value })}
                            required
                            disabled={isSubmitting}
                        >
                            <option value="">-- Select Lot --</option>
                            {lots && lots.length > 0 ? (
                                lots.map(lot => (
                                    <option key={lot.id} value={lot.id}>
                                        {lot.lotName || lot.id} - {lot.processingMethod || 'N/A'} ({lot.status || 'N/A'})
                                    </option>
                                ))
                            ) : (
                                <option value="" disabled>No lots available</option>
                            )}
                        </select>
                    </div>

                    <div className="form-group">
                        <label className="form-label required">Bag Code</label>
                        <input
                            type="text"
                            className="form-input"
                            value={formData.bag_code}
                            onChange={(e) => setFormData({ ...formData, bag_code: e.target.value })}
                            placeholder="e.g., BAG-001"
                            required
                            disabled={isSubmitting}
                        />
                    </div>

                    <div className="form-group">
                        <label className="form-label required">Bag Weight (kg)</label>
                        <input
                            type="number"
                            className="form-input"
                            value={formData.weight_kg}
                            onChange={(e) => setFormData({ ...formData, weight_kg: e.target.value })}
                            step="0.1"
                            min="0"
                            required
                            disabled={isSubmitting}
                        />
                    </div>

                    <div className="form-group">
                        <label className="form-label">Moisture (%)</label>
                        <input
                            type="number"
                            className="form-input"
                            value={formData.moisture}
                            onChange={(e) => setFormData({ ...formData, moisture: e.target.value })}
                            step="0.1"
                            min="0"
                            max="100"
                            disabled={isSubmitting}
                        />
                    </div>

                    <div className="actions-group" style={{ marginTop: 'var(--spacing-lg)' }}>
                        <button type="submit" className="btn btn-primary" disabled={isSubmitting}>
                            {isSubmitting ? 'Creating...' : 'Create Bag'}
                        </button>
                        <button type="button" onClick={() => setIsModalOpen(false)} className="btn btn-outline" disabled={isSubmitting}>
                            Cancel
                        </button>
                    </div>
                </form>
            </Modal>
        </div>
    );
};

export default BagManagement;

import React, { useState } from 'react';
import { useData } from '../../context/DataContext';
import { useAuth } from '../../context/AuthContext';
import { processingAPI, lotsAPI } from '../../services/api';

const ProcessingLogs = () => {
    const { lots, fetchLots, loading } = useData();
    const { user } = useAuth();
    const [selectedLot, setSelectedLot] = useState('');
    const [stage, setStage] = useState('');
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState(null);
    const [successMessage, setSuccessMessage] = useState(null);

    const stages = ['received', 'pulped', 'fermented', 'washed', 'dried', 'stored'];

    const handleAddLog = async (e) => {
        e.preventDefault();
        setError(null);
        setIsSubmitting(true);

        try {
            if (!selectedLot || !stage) {
                setError('Please select both lot and stage');
                setIsSubmitting(false);
                return;
            }

            const startTime = new Date().toISOString();

            // Create processing log
            await processingAPI.create({
                lot_id: selectedLot,
                stage: stage.toUpperCase(),
                start_time: startTime,
                operator_id: user?.id
            });

            // Update lot status
            await lotsAPI.update(selectedLot, {
                status: stage === 'stored' ? 'COMPLETED' : 'IN_PROCESS'
            });

            // Set success message instead of alert
            const selectedLotName = lots.find(l => l.id === selectedLot)?.lotName || selectedLot;
            setSuccessMessage(`Processing log created: ${selectedLotName} - ${stage.charAt(0).toUpperCase() + stage.slice(1)}`);
            setSelectedLot('');
            setStage('');
            await fetchLots();

            // Clear success message after 5 seconds
            setTimeout(() => setSuccessMessage(null), 5000);
        } catch (err) {
            console.error('Error creating processing log:', err);
            setError(err.message || 'Failed to add processing log. Please try again.');
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <div>
            <div className="page-header">
                <h1 className="page-title">Processing Logs</h1>
                <p className="page-description">Record processing stage transitions</p>
            </div>

            <div className="content-card">
                <div className="card-header">
                    <h2 className="card-title">Add Processing Log</h2>
                </div>

                {error && (
                    <div className="alert alert-error" style={{ marginBottom: 'var(--spacing-md)' }}>
                        {error}
                    </div>
                )}

                {successMessage && (
                    <div className="alert alert-success" style={{ marginBottom: 'var(--spacing-md)' }}>
                        {successMessage}
                    </div>
                )}

                <form onSubmit={handleAddLog}>
                    <div className="form-group">
                        <label className="form-label required">Select Lot</label>
                        <select
                            className="form-select"
                            value={selectedLot}
                            onChange={(e) => setSelectedLot(e.target.value)}
                            required
                            disabled={isSubmitting}
                        >
                            <option value="">-- Select Lot --</option>
                            {lots.filter(l => l.status !== 'COMPLETED' && l.status !== 'completed').map(lot => (
                                <option key={lot.id} value={lot.id}>
                                    {lot.lotName || lot.id} - Current: {lot.status}
                                </option>
                            ))}
                        </select>
                    </div>

                    <div className="form-group">
                        <label className="form-label required">Processing Stage</label>
                        <select
                            className="form-select"
                            value={stage}
                            onChange={(e) => setStage(e.target.value)}
                            required
                            disabled={isSubmitting}
                        >
                            <option value="">-- Select Stage --</option>
                            {stages.map(s => (
                                <option key={s} value={s}>{s.charAt(0).toUpperCase() + s.slice(1)}</option>
                            ))}
                        </select>
                    </div>

                    <button type="submit" className="btn btn-primary" disabled={isSubmitting}>
                        {isSubmitting ? 'Adding...' : 'Add Log Entry'}
                    </button>
                </form>
            </div>
        </div>
    );
};

export default ProcessingLogs;

